export const glossaryTerms = [
  { id: 1, term: "가계부실위험지수(HDRI)", definition: "가구의 소득 흐름은 물론 금융 및 실물 자산까지 종합적으로 고려하여 가계부채의 부실위험을 평가하는 지표로, 가계의 채무상환능력을 소득 측면에서 평가하는 원리금상환비율(DSR)과 자산 측면에서 평가하는 부채/자산비율(DTA)을 결합하여 산출한 지수이다. 가계부실위험지수는 가구의 DSR과 DTA가 각각 40%, 100%일 때 100의 값을 갖도록 설정되어 있으며, 동 지수가 100을 초과하는 가구를 '위험가구'로 분류한다.", related: ["총부채원리금상환비율(DSR)"] },
  { id: 2, term: "가계수지", definition: "가정에서 일정 기간의 수입(명목소득)과 지출을 비교해서 남았는지 모자랐는지를 표시한 것을 가계수지(Household's Total Income and Expenditure)라 한다. 가계수지가 흑자를 냈다면 그 가정은 벌어들인 수입 일부만을 사용했다는 것을 의미하며, 적자를 냈다면 수입 외에 빚을 추가로 얻어 사용한 것이라고 보아야 한다.", related: ["경상수지", "재정수지"] },
  { id: 3, term: "가계순저축률", definition: "가계부문의 순저축액을 가계순처분가능소득과 정부로부터 받은 사회적 현물이전 금액, 연금기금의 가계순지분 증감조정액을 합계한 금액으로 나눈 비율이다. 가계순저축률(%) = {가계부문 순저축 / (가계순처분가능소득 + 사회적현물이전수취 + 연금기금의 가계순지분 증감조정)} × 100", related: ["가계처분가능소득", "저축률"] },
  { id: 4, term: "가계신용통계", definition: "가계부문에 대한 신용공급 규모를 나타내는 통계이다. 가계신용은 금융기관뿐 아니라 정부, 판매회사 등 기타기관이 가계에 제공한 대출과 외상구매 관련 신용을 모두 포괄하는 것으로 크게 가계대출과 판매신용으로 구분된다. 현재 가계신용통계는 2002년 말 잔액부터 분기별로 제공되고 있다.", related: [] },
  { id: 5, term: "가계처분가능소득", definition: "가계처분가능소득(PDI; Personal Disposable Income)은 가계가 마음대로 소비와 저축으로 처분할 수 있는 소득을 의미한다. 1인당 가계총처분가능소득(PGDI)은 가계부문의 총처분가능소득을 연앙인구로 나누어 계산한 지표로 가계의 구매력을 가장 정확히 가늠해 볼 수 있는 소득지표이다.", related: ["국민총소득(GNI)"] },
  { id: 6, term: "가교은행", definition: "청산 대상 금융기관의 자산, 부채를 임시로 넘겨받아 예금, 출금 등의 업무를 대행하고 합병, 채권채무관계 조정 등 후속조치를 수행하는 은행을 말한다. 가교은행은 파산 처리가 완료되면 정리대상 금융기관과 마찬가지로 없어지는 한시적 기관이다.", related: [] },
  { id: 7, term: "가산금리", definition: "신용도 등의 차이에 따라 기준금리에 덧붙이는 금리를 가산금리(또는 스프레드, spread)라고 한다. 통상 신용도가 높으면 가산금리가 낮고, 신용도가 낮으면 가산금리 즉 스프레드는 커진다. 금리격차는 보통 베이시스 포인트(bp)로 나타내는데 0.5%의 금리격차를 50bp, 1%는 100bp로 표시된다.", related: ["무위험지표금리(RFR)", "신용스프레드"] },
  { id: 8, term: "가상자산", definition: "가상자산(Virtual Asset)은 분산원장 및 암호화 기술을 바탕으로 민간에 의해 디지털 토큰 형태로 발행되어 전자적으로 거래 또는 이전 가능한 자산이다. 가상자산은 전통적인 현금, 예금 등의 화폐와는 구별되는 새로운 형태의 자산으로서 일부에서 투자 및 지급수단으로 활용되고 있으나, 가격 변동성이 크다.", related: ["블록체인", "비트코인", "중앙은행 디지털화폐(CBDC)"] },
  { id: 9, term: "가상자산공개(ICO)", definition: "가상자산공개(ICO; Initial Coin Offering)는 주로 혁신적인 신생기업이 가상자산 또는 디지털 토큰을 이용하여 자금을 조달하는 크라우드펀딩의 한 방식이다. 기업공개(IPO)에서 연유된 개념으로, ICO에 참여한 투자자는 해당 신생기업의 코인 또는 토큰을 얻는다.", related: ["가상자산", "블록체인", "비트코인", "크라우드펀딩"] },
  { id: 10, term: "간접금융/직접금융", definition: "자금 잉여주체와 자금 부족주체 사이에 은행이나 저축은행 등 금융기관이 개입하여 자금을 중개하는 방식을 간접금융이라고 한다. 주식, 채권 발행의 경우와 같이 자금수요자가 금융기관을 통하지 않고 금융시장에서 직접 필요자금을 조달하는 방식을 직접금융이라고 한다.", related: ["금융제도", "장기금융시장(자본시장)"] },
  { id: 11, term: "간접세/직접세", definition: "납세의무자와 조세부담자가 일치하여 조세부담이 전가되지 않는 조세를 직접세라고 하며, 소득세·법인세·상속세 등이 있다. 납세의무자와 조세부담자가 일치하지 않고 조세의 부담이 타인에게 전가되는 세금을 간접세라고 하며, 부가가치세·개별소비세 등이 있다.", related: [] },
  { id: 12, term: "간편 송금", definition: "모바일 앱이나 온라인 서비스를 통해 상대방에게 손쉽게 금전적 가치를 이전해 주는 서비스이다. 공인인증서나 OTP 없이도 비밀번호 또는 지문인식과 같은 생체인증만으로 송금이 가능하다. 국내에서는 토스, 카카오페이, 네이버페이 등이 이용하고 있다.", related: ["NFC 기술"] },
  { id: 13, term: "감독자협의회(Supervisory College)", definition: "다국적 금융기관들에 대한 효과적인 규제·감독을 위하여 다국적 금융기관의 본점이 소재한 국가(home country)의 감독 당국과 진출국(host country)의 감독 당국들로 구성된 정보공유 및 감독협력 협의체를 의미한다.", related: [] },
  { id: 14, term: "갑기금(Capital A)", definition: "외국은행 국내지점의 대차대조표상 자본금계정으로 본점이 해당 지점에 공급한 원화 자금, 적립금에서 전입하는 자금 등이 해당된다. 각 외은지점의 갑기금은 30억원 이상이어야 한다.", related: ["을기금(Capital B)"] },
  { id: 15, term: "거래정보저장소", definition: "거래정보저장소(TR; Trade Repository)는 장외파생상품(OTC Derivatives) 거래에 대한 상세 정보를 중앙 집중적으로 수집, 보관 및 관리하는 금융시장인프라(FMI)이다. 우리나라에서는 한국거래소(KRX)가 2015년 TR사업자로 선정되어 2021년 4월부터 공식 운영 중이다.", related: ["금융시장인프라"] },
  { id: 16, term: "거시건전성 정책", definition: "개별 금융회사의 부실 방지를 목적으로 하는 미시건전성정책과 달리 경제전체의 금융안정을 위해 시스템 리스크(systemic risk)를 억제하는 정책을 의미한다. 거시건전성정책의 목표는 과도한 금융불균형 축적 억제, 금융시스템의 복원력 강화 등을 통해 금융위기의 발생가능성을 최소화하는 데 있다.", related: [] },
  { id: 17, term: "거액익스포저 규제", definition: "금융기관의 특정 차주 등에 대한 신용공여가 과도한 경우 해당 거래상대방의 채무불이행 등이 발생 시 금융기관의 자본건전성을 심하게 훼손할 가능성(편중리스크)이 있다. 거액익스포저비율(거액익스포저를 은행 기본자본으로 나눈 값)이 25%를 초과하지 못하도록 규정하고 있다.", related: ["동일인 신용공여한도제", "익스포저"] },
  { id: 18, term: "거액지급시스템", definition: "참가기관 간에 주로 거액의 자기자금 또는 고객자금 이체를 위한 지급지시가 이루어지는 시스템을 말한다. 주요국의 거액지급시스템은 대부분 실시간총액결제방식을 채택하고 있으며 대부분 중앙은행이 직접 운영한다. 우리나라의 한은금융망(BOK-Wire+), 미국의 Fedwire 등이 해당된다.", related: ["소액지급시스템", "지급결제시스템"] },
  { id: 19, term: "결제", definition: "결제(Settlement)는 개인이나 기업 등 경제주체가 자금거래 또는 금융자산 거래를 한 후 각각의 지급지시에 따라 자금 또는 증권이 이전되어 법적인 채권·채무가 종결되는 과정이다.", related: ["지급", "청산"] },
  { id: 20, term: "결제리스크", definition: "예기치 못한 사정으로 인하여 결제가 예정대로 이루어지지 않을 가능성 또는 그로 인하여 야기되는 손실발생 가능성으로 정의할 수 있다. 결제리스크는 신용리스크, 유동성리스크, 운영리스크, 법률리스크, 시스템리스크 등으로 세분화된다.", related: ["지급결제시스템"] },
  { id: 21, term: "결제부족자금 공동분담제", definition: "결제부족자금 공동분담제(Loss-Sharing)는 참가기관이 거래에 따른 지급의무를 이행하지 않는 경우 지급되지 않은 채무를 여타 참가기관들이 공동분담함으로써 결제가 완료되도록 보장하는 방안이다. '생존자 분담(survivors pay)' 방식이라고도 한다.", related: ["결제리스크", "차액결제시스템"] },
  { id: 22, term: "결제완결성", definition: "지급결제시스템을 통해 이루어진 참가기관의 지급지시가 결제된 이후에는 어떠한 상황이나 법률에 의해서도 취소되거나 무효화되지 않고 해당 지급결제시스템의 운영 규칙에 따라 무조건적으로 종결되는 것을 의미한다.", related: [] },
  { id: 23, term: "겸업주의/전업주의", definition: "하나의 금융회사가 은행·증권·보험 등 여러 금융서비스를 취급할 수 있는 것을 겸업주의(Universal banking)라 하며, 은행·증권사·보험사 등이 각각 해당하는 고유의 서비스만을 제공하는 방식을 전업주의(Specialized banking)라 한다.", related: ["볼커룰"] },
  { id: 24, term: "경기", definition: "경기(Business Conditions)는 생산, 소비, 투자 등의 경제활동이 평균 수준 이상으로 활발한 경우를 경기가 좋다고 의미한다. 경기는 호황기→후퇴기→불황기→회복기→호황기가 반복되면서 끊임없이 변동하며, 이렇게 경기의 일정한 움직임이 되풀이되는 것을 경기의 순환(business cycle)이라고 한다.", related: ["경기종합지수", "동행종합지수"] },
  { id: 25, term: "경기순응성", definition: "경기순응성이란 경제주체의 위험인식 및 행위, 금융의 제도 및 규제 등의 효과가 경기변동의 움직임과 같은 방향으로 움직이는 것을 의미한다. 예를 들어 은행대출의 경우 호경기에는 여신심사기준이 완화되어 더 크게 증가하고, 불경기에는 심사기준이 강화되어 대출이 큰 폭으로 감소한다.", related: ["거시건전성 정책"] },
  { id: 26, term: "경기조절정책/경제안정화정책", definition: "경기조절정책은 경기가 지나친 확장 또는 수축 현상을 보일 경우 이를 정상 수준으로 되돌리기 위해 정책당국이 취하는 제반 조치를 말한다. 정부지출과 세율을 조정하는 재정정책이나 통화량과 금리 수준을 조절하는 통화정책이 활용된다.", related: ["재정정책", "통화정책"] },
  { id: 27, term: "경기종합지수", definition: "개별 경제지표들을 가공·합성하여 경기종합지수(CI; Composite Index)를 작성하고 있다. 경기종합지수는 경기에 대한 선·후행 관계에 따라 선행종합지수, 동행종합지수, 후행종합지수로 구분한다. 선행종합지수는 비교적 가까운 장래의 경기 동향을 예측하는 데 활용된다.", related: ["경기"] },
  { id: 28, term: "경상수지", definition: "경상수지는 재화나 서비스를 외국과 사고파는 거래 즉 경상거래의 결과로 나타나는 수지를 말한다. 경상수지는 상품수지, 서비스수지, 본원소득수지 및 이전소득수지로 구성된다.", related: ["상품수지", "서비스수지", "본원소득수지", "이전소득수지"] },
  { id: 29, term: "경영실태평가/은행경영실태 평가등급제도", definition: "경영실태평가는 금융감독당국이 임점 검사 시 금융기관의 경영실태 전반을 점검·평가하기 위한 제도로, 각 금융기관의 경영실적, 경영의 건전성, 경영진의 경영능력, 법규준수 상황 및 리스크 관리실태 등을 종합적으로 평가한다. 평가등급은 1등급(우수)~5등급(위험)의 5단계로 구분된다.", related: ["CAMEL-IR 방식"] },
  { id: 30, term: "경제 서프라이즈 지수", definition: "경제 서프라이즈 지수(ESI; Economic Surprise Index)는 실제로 발표된 경제지표가 시장의 전망치(예상치, 컨센서스)와 얼마나 차이가 있는지를 수치로 나타내는 지표이다. 지수가 양수(+)이면 실제 경제지표가 예상보다 호조이고, 음수(-)이면 예상보다 부진함을 의미한다.", related: [] },
  { id: 31, term: "경제성장률", definition: "경제성장률이란 일정 기간 중 한 나라의 경제규모, 즉 국민소득 규모가 늘어난 정도를 백분율로 표시한 것이다. 경제성장률 = (금년 실질GDP - 전년 실질GDP) / 전년 실질GDP", related: ["잠재GDP성장률"] },
  { id: 32, term: "경제심리지수", definition: "경제심리지수(ESI; Economic Sentiment Index)는 기업경기실사지수(BSI)와 소비자동향지수(CSI)를 합성하여 민간의 경제상황에 대한 인식을 종합적으로 평가할 수 있는 지수이다. ESI가 100을 넘으면 현재 민간의 경제심리가 과거 평균보다 낙관적임을 나타낸다.", related: ["기업경기실사지수(BSI)", "소비자동향지수(CSI)"] },
  { id: 33, term: "경제전망보고서", definition: "다양한 경제지표와 세계 경제 동향 등을 바탕으로 향후 경제 상황이 어떻게 전개될지를 분석하고 예측한 보고서를 말한다. 경제성장률 전망, 인플레이션 전망, 고용 전망, 환율 전망, 경상수지 전망 등이 포함된다.", related: ["경제성장률", "인플레이션", "경상수지", "경기"] },
  { id: 34, term: "경제협력개발기구(OECD)", definition: "1961년 9월 설립된 국제기구로 설립목적은 회원국의 경제성장과 금융안정을 도모하고 세계무역 확대에 기여하는 것이다. 현재 회원국 수는 38개국(2025년 기준)이며 우리나라는 1996년 12월에 가입하였다.", related: [] },
  { id: 35, term: "경제활동인구/비경제활동인구/경제활동참가율", definition: "만15세 이상 인구 중 일할 수 있는 능력과 취업의사를 동시에 갖춘 사람을 경제활동인구라 한다. 경제활동참가율 = 경제활동인구(취업자 + 실업자) / 15세 이상 인구 × 100", related: ["고용보조지표", "잠재경제활동인구"] },
  { id: 36, term: "경제후생지표", definition: "복지지표로서 한계성을 갖는 국민총소득(GNI)을 보완하기 위해 미국의 노드하우스(W. Nordhaus)와 토빈(J. Tobin)이 제안한 새로운 지표이다. 경제후생지표(MEW; Measure of Economic Welfare)는 국민총소득에 후생요소를 추가하고, 비후생요소를 제외함으로써 복지수준을 정확히 반영하려는 취지로 제안되었다.", related: ["국민총소득(GNI)"] },
  { id: 37, term: "경직적 물가지수", definition: "소비자물가지수를 구성하는 품목 중 경직적으로 움직이는 품목들을 대상으로 만든 물가지수이다. 공공서비스, 전기·수도, 담배, 보육·급식 가격이나 개인서비스 요금 등은 대체로 가격이 쉽게 오르거나 내리지 않는 특징을 보인다. 경직적 물가의 변동은 장기적인 인플레이션 흐름을 잘 반영한다.", related: ["근원인플레이션율"] },
  { id: 38, term: "계절변동조정시계열", definition: "원래의 시계열에서 계절요인을 여러 통계적 기법을 이용하여 제거한 것을 말한다. 계절변동을 고려하지 않고 기간별로 시계열의 증감을 비교하면 왜곡이 있을 수 있으므로 전월 또는 전분기 대비 증감 비교시 계절변동조정이 필요하다.", related: ["경제성장률"] },
  { id: 39, term: "계좌대체", definition: "증권거래시 실물증권을 주고받는 대신 양자 모두 계좌를 가진 중앙예탁기관 내에서 계좌간 이전하는 방식으로 장부상 처리하는 것을 말한다. 우리나라는 한국예탁결제원이 계좌간 대체 방식으로 증권 이전을 처리하고 있다.", related: ["중앙예탁기관"] },
  { id: 40, term: "고객확인절차(KYC)", definition: "고객확인절차(KYC; Know Your Customer)는 테러자금조달 및 자금세탁 등 불법거래 차단을 위해 관계당국이 부여한 의무에 따라 고객의 신원을 식별하고 확인하는(verify) 업무절차를 뜻한다.", related: ["가상통화", "비트코인"] },
  { id: 41, term: "고용률", definition: "고용률은 15세 이상 인구 중에서 취업자가 차지하는 비율을 말한다. 고용률(%) = 취업자 / 15세이상인구 × 100. 고용률은 실업률 통계의 한계점을 해소할 수 있기 때문에 고용통계에서 중요한 개념이다.", related: ["고용보조지표", "실업률"] },
  { id: 42, term: "고용보조지표", definition: "기존의 공식 실업률만으로는 노동시장을 제대로 반영하는데 한계가 있어 2014년 11월부터 새로운 고용보조지표를 발표하고 있다. 고용보조지표는 시간관련 추가취업 가능자, 잠재구직자, 잠재취업가능자 등을 포함하여 산출한다.", related: ["실업률", "잠재경제활동인구"] },
  { id: 43, term: "고용유발효과/취업유발효과", definition: "최종수요의 발생이 생산을 유발하고 생산이 다시 노동수요를 유발하는 파급 메커니즘에 기초하여 최종수요와 노동유발을 연결시킴으로써 분석한다. 노동계수에 고용계수를 이용하면 고용유발계수, 취업계수를 이용하면 취업유발계수라 한다.", related: ["생산유발효과"] },
  { id: 44, term: "고정금리", definition: "고정금리란 최초 약정한 금리가 만기까지 그대로 유지되는 금리를 의미하며 변동금리란 일정 주기별로 시장금리를 반영하여 약정금리가 변동하는 금리를 의미한다. 자금 차입자 입장에서는 앞으로 시장금리가 상승할 것으로 예상하는 경우에는 고정금리를 이용하는 것이 유리하다.", related: ["변동금리", "양도성예금증서(CD)"] },
  { id: 45, term: "고정금리부채권(SB)", definition: "고정금리부채권(Straight Bond)이란 정해진 기일에 고정된 이자를 지급하고 정해진 만기에 원금을 지급하는 가장 일반적인 형태의 채권이다. 이에 대비되는 채권으로 변동금리부채권(FRN; Floating Rate Note)이 있다.", related: ["변동금리부채권(FRN)"] },
  { id: 46, term: "고정이하여신비율", definition: "은행은 보유하고 있는 여신을 '정상', '요주의', '고정', '회수의문', '추정손실'의 5단계로 분류하여 관리하고 있다. 이중 고정, 회수의문, 및 추정손실로 분류된 여신의 합계액을 총여신으로 나눈 비율을 고정이하여신비율이라고 한다.", related: ["자산건전성 분류"] },
  { id: 47, term: "고정자본소모", definition: "생산에 이용된 기계 등 자산의 가치 감소분을 고정자본소모(Consumption of Fixed Capital)라고 한다. 순생산액 = 총생산액(산출액 - 중간투입액) - 고정자본소모", related: ["총고정자본형성"] },
  { id: 48, term: "고정환율제도/자유변동환율제도", definition: "고정환율제도는 환율을 정부나 중앙은행이 적정하다고 판단하는 수준으로 일정하게 유지하는 제도이다. 자유변동환율제도는 환율이 외환의 수요와 공급에 의해 자율적으로 결정되도록 하는 환율제도이다. 어떤 환율제도를 채택하더라도 세 가지 정책목표를 동시에 달성하기 어렵다는 삼불원칙(impossible trinity)이 있다.", related: ["삼불원칙", "외환시장"] },
  { id: 49, term: "고통지수", definition: "소비자물가상승률과 실업률을 더한 값으로 1975년 미국의 경제학자 오쿤(A. Okun)이 만든 국민의 삶의 질을 측정하기 위한 지표이다. 이 수치가 높을수록 실업자는 늘고 물가는 높아져 한 나라의 국민이 느끼는 삶의 고통이 늘어남을 의미한다.", related: ["소비자물가지수(CPI)", "실업률"] },
  { id: 50, term: "골디락스경제", definition: "골디락스경제(Goldilocks Economy)는 경기과열에 따른 인플레이션과 경기침체에 따른 실업을 염려할 필요가 없는 최적 상태에 있는 건실한 경제를 가리킨다. 영국의 전래동화인 골디락스와 곰 세 마리에 등장하는 금발머리 소녀의 이름에서 유래하였다.", related: ["대안정기", "장기침체"] },
  { id: 51, term: "공개시장운영", definition: "공개시장운영(Open Market Operation)은 중앙은행이 금융시장에서 금융기관을 상대로 증권을 매매하여 시중유동성이나 시장금리 수준에 영향을 미치는 통화정책수단이다. 대부분의 선진국 중앙은행들은 공개시장운영을 주된 통화정책수단으로 사용하고 있다.", related: ["통화정책수단"] },
  { id: 52, term: "공공재", definition: "공공재는 모든 개인이 공동으로 이용할 수 있는 재화 또는 서비스를 의미한다. 공공재의 성질로는 어떤 사람의 소비가 다른 사람의 소비를 방해하지 않는 비경쟁성·비선택성, 대가를 지급하지 않은 특정 개인을 소비에서 제외하지 않는 비배제성 등을 들 수 있다.", related: ["자유재"] },
  { id: 53, term: "공급병목", definition: "제품이나 서비스가 생산자로부터 소비자에게 전달되는 특정 단계에서 원활한 흐름이 이루어지지 않아 전체 공급망이 지연되거나 막히는 현상을 말한다. 공급병목이 생기면 관련 물품의 공급 부족으로 물가가 상승하고 경기가 나빠지게 된다.", related: ["글로벌 공급망 압력지수", "경기"] },
  { id: 54, term: "공급사용표(SUT)", definition: "산업연관표는 투입산출표(Input-Output Tables)와 공급사용표(Supply and Use Tables)로 구성되는데, 투입산출표는 상품을 기준으로, 공급사용표는 산업을 기준으로 생산내역을 나타낸 표이다.", related: ["국민계정체계(SNA)", "국민대차대조표"] },
  { id: 55, term: "공급탄력성", definition: "공급탄력성은 가격변화에 대한 공급의 민감도를 측정하는 척도이다. 공급탄력성 = 공급량의 변화율 ÷ 가격의 변화율. 1%의 가격 상승이 1%보다 더 큰 공급량 증가를 가져오면 공급은 탄력적이라 한다.", related: ["수요탄력성"] },
  { id: 56, term: "공동부유", definition: "공동부유(共同富裕, Common Prosperity)는 시진핑 중국 국가주석이 2021년 이후 강조한 주요 정책 방향 중 하나로서 소수만 부유해지는 것이 아니라 사회 전체가 균형 있게 번영하고 부를 나누어 모든 국민이 함께 잘사는 사회를 만들자는 것을 의미한다.", related: ["독점/과점"] },
  { id: 57, term: "공매도", definition: "공매도(Short Selling)는 주식시장에서 투자자가 주식을 보유하지 않은 상태에서 주가 하락을 예상하고 금융기관으로부터 주식을 빌려 먼저 매도한 후, 주가가 하락하면 시장에서 주식을 매입하여 되갚은 후 차익을 얻는 투자를 말한다.", related: [] },
  { id: 58, term: "관리변동환율제도", definition: "환율이 장기적으로 외환시장의 수급 상황에 따라 결정되도록 하지만, 단기적으로는 정부와 중앙은행이 외환시장에 개입하여 환율 수준을 관리하는 환율제도이다. 고정환율제도와 자유변동환율제도의 장점을 살린 중간 형태라 할 수 있다.", related: ["고정환율제도/자유변동환율제도", "외환시장"] },
  { id: 59, term: "관리통화제도", definition: "관리통화제도는 금본위제도와는 달리 중앙은행이 통화량을 직접 조절하여 경제를 안정시키는 제도이다. 중앙은행은 기준금리 조정, 공개시장운영, 지급준비율 변경 등 주요 정책수단을 통해 인플레이션을 억제하거나 경기를 조절한다.", related: ["금본위제도"] },
  { id: 60, term: "광의통화(M2)", definition: "광의통화(M2)는 경제 내에 유통되는 화폐규모를 측정하는 통화지표의 하나로서, 협의통화(M1) 외에도 만기 2년 이내의 정기예금, 정기적금, 금융채, 수익증권 등 단기간 내 현금화가 가능한 금융상품까지 포함된다.", related: ["통화지표", "통화량"] },
  { id: 61, term: "교환사채(EB)", definition: "교환사채(EB; Exchangeable Bond)란 사채권자의 의사에 따라 교환사채 발행기업이 보유하고 있는 타사 주식 등 여타의 유가증권과 교환할 수 있는 선택권이 부여된 사채를 말한다.", related: ["신주인수권부사채(BW)", "전환사채(CB)"] },
  { id: 62, term: "교환성 통화", definition: "국제적인 통용력을 가진 특정 국가의 통화를 말한다. 현재는 외환시장에서 미국의 달러화와 자유로이 교환 가능한 통화라는 의미로 사용되고 있다. 현재 SDR 바스켓을 구성하고 있는 미 달러화, 유로화, 파운드화, 엔화 및 위안화를 교환성 통화로 볼 수 있다.", related: ["기축통화", "특별인출권(SDR)"] },
  { id: 63, term: "구독경제", definition: "소비자가 제품이나 서비스를 소유하지 않은 채 일정한 금액을 주기적으로 지불하면서 사용하는 경제 모델을 말한다. 즉, 사는 것이 아니라 빌려 쓰고 구독하는 것에 초점을 둔 소비 방식이다.", related: [] },
  { id: 64, term: "구매력평가 환율", definition: "구매력평가(PPP; Purchasing Power Parity) 환율은 해당 통화의 실질 구매력을 기준으로 평가한 환율이다. 관련 당사국 간 물가수준의 차이에 의해 균형 환율이 결정된다는 구매력평가이론에 근거하고 있다. 대표적 구매력평가환율로는 '빅맥지수'를 들 수 있다.", related: ["빅맥지수", "일물일가의 법칙"] },
  { id: 65, term: "구인배수", definition: "노동의 수요와 공급 상황을 나타내는 지표로서 일자리수를 취업 희망자수로 나누어 구하는데 인력수급동향을 파악하는데 주로 이용된다. 구인배수 0.7은 취업 희망자 열 명당 일곱 개의 일자리가 있다는 의미로 수치가 높을수록 고용사정이 좋다.", related: ["고용률", "실업률갭"] },
  { id: 66, term: "국가경쟁력", definition: "국가경쟁력은 한 나라가 경제성장을 지속하고, 국민들의 삶의 질을 향상시킬 수 있는 능력을 말한다. 대표적인 국가경쟁력 지표로 스위스 국제경영개발원(IMD)에서 발표하는 세계경쟁력순위(WCR)가 있다.", related: [] },
  { id: 67, term: "국가신용등급", definition: "한 나라가 채무를 이행할 능력과 의사가 얼마나 있는지를 평가하여 등급으로 표시한 것으로 국제금융시장에서 차입금리나 투자여건을 판단하는 기준이 된다. 미국의 S&P, 무디스, 영국의 피치 등 국제신용평가기관이 평가한다.", related: ["무디스", "스탠더드&푸어스"] },
  { id: 68, term: "국가채무", definition: "국가채무란 정부가 재정적자 보전 등을 목적으로 국내외로부터 자금을 차입함으로써 발생하는 채무를 말한다. 국가채무는 한 번 누적되면 새로운 재정적자가 발생하지 않더라도 기존채무에 대한 이자지급 부담으로 채무가 계속 늘어나는 자기증식의 속성을 가지고 있다.", related: ["기대인플레이션"] },
  { id: 69, term: "국고금 실시간 전자이체", definition: "정부가 지급할 국고금이 실시간으로 각 채권자의 예금계좌로 바로 입금되게 하는 것을 말한다. 정부의 통합재정정보시스템과 한국은행 및 금융기관의 전산시스템을 연결해 2003년 1월부터 시행되었다.", related: ["국고수표", "국고전산망"] },
  { id: 70, term: "국고대리점", definition: "한국은행의 한정된 조직과 인력만으로는 전국의 국고금 납부자에게 충분한 편의를 제공하기 어렵기 때문에 금융기관 영업점을 국고 대리점으로 지정하여 국고금 수납사무를 위탁하고 있다.", related: [] },
  { id: 71, term: "국고수표", definition: "국고수표는 지출관이 국고금 지출을 위하여 발행하는 수표로 과거 국고금의 기본지급수단이었으나 2003년 1월 1일부터 국고금 실시간 전자이체제도가 실시됨으로써 실질적으로 사용하지 않고 있다.", related: ["국고금 실시간 전자이체", "국고전산망"] },
  { id: 72, term: "국고전산망", definition: "2003년 1월 한국은행이 국고업무를 전자적으로 처리하기 위하여 구축한 전산망으로 정부, 한국은행, 금융기관 및 금융결제원의 전산시스템을 연결한다. 국고전산망 운영시간은 오전 9시부터 오후 4시까지이다.", related: ["국고금 실시간 전자이체"] },
  { id: 73, term: "국내공급물가지수", definition: "국내공급물가지수는 생산자물가지수와 수입물가지수를 결합하여 국내시장에 공급되는 상품 및 서비스의 종합적인 가격 수준을 지수화한 것이다. 생산단계별로 원재료, 중간재 및 최종재로 지수가 구분되기 때문에 물가변동의 파급과정을 파악하는데 용이하다.", related: ["생산자물가지수(PPI)", "수출입물가지수"] },
  { id: 74, term: "국내총생산(GDP)", definition: "국내총생산(GDP; Gross Domestic Product)은 한 나라의 영역 내에서 가계, 기업, 정부 등 모든 경제주체가 일정 기간 생산활동에 참여하여 창출한 부가가치 또는 최종 생산물을 시장가격으로 평가한 합계이다. 명목GDP는 국가경제의 규모나 구조 등을 파악하는 데 사용되며 실질GDP는 경제성장, 경기변동 등을 분석하는 데 이용된다.", related: ["국민총소득(GNI)"] },
  { id: 75, term: "국내총투자율", definition: "국내총투자율(Gross Domestic Investment Ratio)은 국민경제가 구매한 재화 중에서 자산의 증가로 나타난 부분이 국민총처분가능소득에서 차지하는 비율을 의미한다.", related: ["국민총처분가능소득"] },
  { id: 76, term: "국민계정체계(SNA)", definition: "국민계정체계(SNA; System of National Accounts)는 기존의 산업연관표, 국민소득통계, 자금순환표, 국제수지표 등 별개로 파악하고 있던 국민계정관련 통계를 통합, 각종 경제분석에 적합하도록 체계적으로 작성한 것이다.", related: ["국내총생산(GDP)", "산업연관표", "국민대차대조표"] },
  { id: 77, term: "국민대차대조표", definition: "국민대차대조표(National Balance Sheet)는 특정 시점에서 국민경제 또는 각 경제주체가 보유하고 있는 유·무형 실물자산 및 금융자산/부채의 가액과, 자산에서 부채를 차감한 순자산을 기록한 스톡통계이다.", related: ["국민계정체계(SNA)"] },
  { id: 78, term: "국민부담률", definition: "국민부담률(total tax revenue as percentage of GDP)이란 조세와 사회보장기여금이 명목 국내총생산(GDP)에서 차지하는 비중(조세부담률+사회보장부담률)을 말한다.", related: ["조세부담률"] },
  { id: 79, term: "국민소득", definition: "국민소득(NI; National Income)은 한 나라 국민이 제공한 생산요소에서 발생한 소득의 총액으로, 노동에 대한 대가인 피용자보수와 자본 및 경영에 대한 대가인 영업잉여의 합계이다. NI = 피용자보수 + 영업잉여 = 임금 + 지대 + 이자 + 이윤", related: ["국민총소득(GNI)"] },
  { id: 80, term: "국민소득 3면 등가의 법칙", definition: "국내총생산(GDP)은 생산, 지출, 분배의 세 측면에서 측정할 수 있으며 이론적으로 각 측면에서 측정된 값은 차이가 없게 된다. 즉 생산GDP = 지출GDP = 분배GDP의 관계가 성립한다.", related: ["국내총생산(GDP)"] },
  { id: 81, term: "국민연금", definition: "일정기간 동안 보험료를 납부하면 노후에 연금을 지급받아 기본적인 생활을 보장받을 수 있도록 설계된 공적 연금 제도이다. 만 18세 이상~60세 미만의 대한민국 국민을 대상으로 운영한다. 노령연금, 장애연금, 유족연금 등이 있다.", related: ["합계출산율", "인구고령화"] },
  { id: 82, term: "국민처분가능소득(NDI)/국민총처분가능소득(GNDI)", definition: "국민처분가능소득(NDI; National Disposable Income)은 나라 경제 전체가 소비나 저축으로 자유로이 처분할 수 있는 소득으로서 거주자와 비거주자 간의 소득이전이 반영된 것이다. 국민총처분가능소득(GNDI) = 최종소비지출 + 총저축", related: ["국민총소득(GNI)"] },
  { id: 83, term: "국민총소득(GNI)", definition: "국민총소득(GNI; Gross National Income)은 한 나라의 국민이 일정 기간 동안 벌어들인 임금, 이자, 배당 등의 소득을 모두 합친 것이다. 국민총소득(명목기준) = GDP + 국외순수취요소소득", related: ["국내총생산(GDP)", "국외순수취요소소득"] },
  { id: 84, term: "국부펀드", definition: "국부펀드(Sovereign Fund)는 주로 투자수익을 목적으로 다양한 종류의 국내외 자산에 투자·운용하는 국가 보유 투자기금을 말한다. 소유권이 민간이 아니라 국가에 있다는 점에서 사모펀드, 연기금 등과 근본적인 차이가 있다. 우리나라는 2005년 7월 한국투자공사(KIC)를 설립하였다.", related: ["외환보유액", "헤지펀드"] },
  { id: 85, term: "국외순수취경상이전", definition: "국외순수취경상이전은 거주자와 비거주자 간에 반대급부 없이 일어나는 이전거래로 국외수취경상이전에서 국외지급경상이전을 차감하여 구하며 거래주체에 따라 민간이전과 공공이전으로 구분할 수 있다.", related: ["국민총소득(GNI)", "국민처분가능소득(NDI)"] },
  { id: 86, term: "국외순수취요소소득", definition: "국외순수취요소소득은 한 나라의 국민이 국외에서 노동, 자본 등의 생산요소를 제공한 대가로 받은 국외수취요소소득에서 국내의 외국인이 생산활동에 참여함으로써 발생한 국외지급요소소득을 차감한 것이다.", related: ["국내총생산(GDP)", "국민총소득(GNI)"] },
  { id: 87, term: "국외저축", definition: "국민경제에서 투자가 저축을 초과하게 되면 부족한 돈을 국외로부터 조달하게 되는데 이를 국외저축(foreign savings)이라고 한다. 국외저축이 양(+)인 것은 경상수지 적자에 대응된다.", related: ["저축률", "투자율"] },
  { id: 88, term: "국외투자율", definition: "국외투자율은 국민총처분가능소득(GNDI) 중 총저축에서 국내투자를 차감한 부분이 차지하는 비율을 의미한다. 총투자율(%) = 국내총투자율(%) + 국외투자율(%) = 총저축률(%)", related: ["국민총처분가능소득", "총투자율", "총저축률"] },
  { id: 89, term: "국제결제은행(BIS)", definition: "BIS(Bank for International Settlements)는 1930년 헤이그협정을 모체로 설립된 세계에서 가장 오래된 국제금융기구로서 중앙은행 간 정책협력을 주요기능으로 하고 있으며 현재 60개 중앙은행이 회원으로 참여하고 있다.", related: [] },
  { id: 90, term: "국제금융시장", definition: "국제금융시장이란 국경을 넘어 자금의 수요와 공급을 연결해 주는 시장 또는 모든 거래 메커니즘을 말한다. 외환시장, 단기 금융시장, 중장기 금융시장, 주식시장 및 파생금융상품시장 등을 포괄한다.", related: ["국제금융중심지"] },
  { id: 91, term: "국제금융중심지", definition: "국제금융시장의 요건을 갖추고 있어 세계적 금융기관들이 본점, 지점, 현지법인의 형태로 영업망을 집중시킴으로써 대량의 국제금융거래가 지속적, 반복적으로 이루어지는 장소를 말한다. 대표적인 국제금융중심지로는 뉴욕, 런던, 동경 등이 있다.", related: ["국제금융시장"] },
  { id: 92, term: "국제산업연관표", definition: "국제산업연관표(International Input-Output Tables)란 국가 간 수출입을 매개로 여러 나라의 산업연관표를 연결하여 하나의 산업연관표로 작성한 것이다. 글로벌 가치사슬 분석(GVC) 등에 활용하고 있다.", related: ["산업연관표(I/O Tables)"] },
  { id: 93, term: "국제수지(BOP)", definition: "일정 기간 동안 한 나라의 거주자와 비거주자 간에 발생한 경제적 거래에 수반되는 수입과 지급의 차이를 의미한다. 국제수지(BOP; Balance Of Payments)는 크게 경상수지, 자본수지, 금융계정, 오차 및 누락 등 4개의 계정으로 구성된다.", related: ["경상수지", "국제수지표"] },
  { id: 94, term: "국제수지표", definition: "일정 기간 동안 한 나라의 거주자와 비거주자 간에 발생한 경제적 거래를 국제기준에 따라 체계적으로 기록한 표이다. 우리나라는 한국은행에서 국제수지표를 매월 작성하여 공표하고 있다.", related: ["국제수지(BOP)", "경상수지"] },
  { id: 95, term: "국제원유가격", definition: "국제원유시장의 대표 유종은 미국 서부텍사스유(WTI), 영국 브렌트유, 아랍에미레이트(UAE) 두바이유의 세 가지이다. 국제원유가격은 장기적으로 원유 수요와 공급에 의해 결정되나 원유 공급지의 지정학적 리스크와 기상, 미달러화 가치 등 많은 요인의 영향을 받는다.", related: ["선물거래"] },
  { id: 96, term: "국제증권감독기구(IOSCO)", definition: "국제증권감독기구(IOSCO; International Organization of Securities Commissions)는 전 세계의 증권 규제기관들이 모인 국제적인 기구로서 130여개 국가가 회원국으로 참여하고 있다. 증권 시장의 안전성과 공정성을 보장하고, 투자자 보호를 위해 국제적인 규제 기준을 마련하는 것을 목표로 한다.", related: ["금융시장인프라(FMI)"] },
  { id: 97, term: "국제통화기금(IMF)", definition: "국제통화 및 금융제도의 안정을 도모하기 위한 국제금융기구로서 미국 워싱턴에 본부를 두고 1945년 12월 설립되었다. 설립목적은 국제통화문제에 관한 협력, 국제무역의 확대와 세계 경제의 균형적 성장, 외환의 안정 촉진 등이다.", related: ["IMF 쿼타", "특별인출권(SDR)"] },
  { id: 98, term: "국제통화시장(IMM)", definition: "국제통화시장(IMM; International Monetary Market)은 1972년 미국 시카고상업거래소(CME) 내에 설립된 세계 최초의 통화선물 전문거래소이다. 달러, 유로, 엔, 파운드 등 주요 국제통화의 선물 및 옵션 상품이 거래된다.", related: ["시카고상업거래소"] },
  { id: 99, term: "국제투자대조표(IIP)", definition: "국제투자대조표(IIP; International Investment Position)는 일정 시점 현재 한 나라 거주자의 비거주자에 대한 금융자산(대외투자) 및 금융부채(외국인투자) 잔액을 기록한 통계표이다. 한국은행에서 매분기 작성하여 발표하고 있다.", related: ["국제수지(BOP)"] },
  { id: 100, term: "국제회계기준", definition: "국제회계기준(IFRS; International Financial Reporting Standards)은 기업의 회계처리와 재무제표에 대한 국제적 정합성을 높이기 위해서 국제회계기준위원회(IASB)가 제정한 회계처리기준을 말한다. 우리나라는 상장회사는 2011년부터 전면 도입하였다.", related: [] },
  { id: 101, term: "국채", definition: "국채란 정부가 다양한 목적의 재정자금을 조달하기 위해 발행하는 채권을 말한다. 국채는 자금 용도에 따라 국고채권, 재정증권, 국민주택채권 및 보상채권으로 나누어지는데 국고채권이 국채의 대부분을 차지한다.", related: [] },
  { id: 102, term: "국채선물", definition: "국채선물이란 국가가 발행하는 채권을 기초자산으로 하는 선물거래를 의미한다. 현재 한국거래소에는 3년, 5년, 10년, 30년 만기 국채선물이 거래되고 있다.", related: ["채권시가평가제도", "시카고상업거래소(CME)"] },
  { id: 103, term: "규모의 경제", definition: "기업이 재화 및 서비스 생산량을 늘려감에 따라 평균비용이 감소하는 현상을 규모의 경제(Economies of Scale)라고 한다. 반도체, 자동차, 항공기, 철강, 석유화학, 유통 및 물류 등의 산업에서 흔히 나타난다.", related: ["범위의 경제"] },
  { id: 104, term: "규제 샌드박스", definition: "규제 샌드박스(Regulatory Sandbox)는 핀테크 기업이 현행 규제를 적용받지 않으면서 자신의 혁신적인 금융상품과 비즈니스모델을 시험할 수 있는 공간이나 제도를 뜻한다. 영국의 금융행위규제청(FCA)이 핀테크 전담조직을 설치하며 도입한 것이다.", related: ["핀테크", "로보어드바이저"] },
  { id: 105, term: "그램-리치-블라일리법", definition: "1999년 11월 미국 의회가 제정한 법으로, 1933년의 글래스-스티걸법 중 '상업은행의 증권 관련 자회사 보유 금지'와 '상업은행과 투자은행의 임직원 겸직 금지' 등 핵심 조항을 폐지하는 것이 주된 내용이다.", related: ["글래스-스티걸법", "투자은행"] },
  { id: 106, term: "그린본드", definition: "그린본드는 조달 자금을 기후 및 환경 관련 사업에 사용하는 것을 전제로 발행되는 특수목적 채권이다. 2007년 최초 발행 이후 초기에는 주로 EIB, World Bank 등 국제기구가 발행을 주도하였으나 최근에는 정부기관, 기업 및 금융기관 등으로 발행기관의 범위가 확대되었다.", related: [] },
  { id: 107, term: "그림자금융/비은행금융중개(NBFI)", definition: "집합투자기구(MMF·채권형·혼합형 펀드 등), RP 거래, 유동화기구 등과 같이 은행시스템 밖에서 신용중개기능을 수행하지만 은행 수준의 건전성 규제와 예금자보호가 적용되지 않는 기관 또는 활동이다.", related: [] },
  { id: 108, term: "근원인플레이션율", definition: "근원인플레이션율(Core Inflation Rate)은 물가변동을 초래하는 여러 요인들 가운데 일시적인 공급충격의 영향을 제외한 기조적인 물가상승률을 말한다. 일반적으로 전체 소비자물가 상승률에서 농산물가격, 국제원자재가격 등의 변동 부분을 제거하여 계산한다.", related: ["기대인플레이션", "인플레이션"] },
  { id: 109, term: "글래스-스티걸법", definition: "미국 의회가 제정한 법으로 공식 명칭은 '1933년 은행법(Banking Act of 1933)'이다. 동 법의 핵심 내용은 기존 은행을 상업은행과 투자은행으로 구분하고 이들의 업무를 엄격하게 분리하려는 것이다.", related: ["그램-리치-블라일리법", "투자은행"] },
  { id: 110, term: "글로벌 가치사슬(GVC)", definition: "글로벌 가치사슬(GVC; Global Value Chain)은 상품의 설계, 부품과 원재료의 조달, 생산, 유통, 판매에 이르기까지 각 세분화된 과정이 비용면에서 우위가 있는 국가에서 이루어지면서 각 단계별로 부가가치가 창출되는 세계교역의 패러다임을 말한다.", related: ["리쇼어링/니어쇼어링/프렌드쇼어링"] },
  { id: 111, term: "글로벌 공급망 압력 지수", definition: "글로벌 공급망 압력지수(GSCPI; Global Supply Chain Pressure Index)는 국제 교역이 이루어지는 과정에서 공급망이 얼마나 원활히 작동하는지 보여주는 지표이다. 미국 뉴욕 연방준비은행이 매달 발표하고 있다.", related: ["인플레이션", "경기"] },
  { id: 112, term: "글로벌금융안전망", definition: "금융위기 등으로 인하여 외화유동성이 부족해지는 경우에 대비하기 위하여 각국이 외화유동성을 인출하거나 지원받는 각종 제도적 장치들을 총칭하여 글로벌금융안전망이라고 한다.", related: ["외환보유액", "지역금융협정", "치앙마이 이니셔티브(CMI)"] },
  { id: 113, term: "글로벌 금융위기", definition: "글로벌 금융위기는 전 세계 금융시스템에 심각한 혼란을 일으키는 위기 상황을 의미한다. 2008년 미국에서 시작된 글로벌 금융위기는 미국 서브프라임 모기지 부실에서 비롯되어 전 세계적인 경기침체를 초래하였다.", related: ["주택저당채권(MBS)", "양적 완화"] },
  { id: 114, term: "금리선물", definition: "금리선물(Interest Rate Futures)이란 기초자산인 금리를 거래대상으로 하며 현재의 시점에서 정한 가격으로 미래의 특정 시점에서 사거나 팔 것을 약정하는 계약을 말한다. 대표적인 상품은 국채선물이다.", related: [] },
  { id: 115, term: "금리스왑", definition: "금리스왑(IRS; Interest Rate Swaps)이란 금리변동위험 헤지 및 차입비용 절감 등을 위하여 거래당사자간에 원금교환 없이 정기적으로 변동금리와 고정금리를 교환하는 거래를 말한다.", related: [] },
  { id: 116, term: "금리자유화", definition: "금리자유화란 금리규제를 철폐함으로써 금리가 시장의 자금수급에 따라 자유로이 결정될 수 있도록 하는 조치이다. 우리나라는 1991년 8월 수립된 '4단계 금리자유화 추진계획'에 따라 1995년 11월 제3단계 금리자유화를 완결하였다.", related: [] },
  { id: 117, term: "금리평가이론", definition: "완전한 금융시장에서 양국 간의 금리 차는 선물환 프리미엄(또는 스왑레이트)과 같다는 이론이다. F-S/S ≒ i-i* 즉, 양국 간 금리 차는 현물환율(S)과 선물환율(F) 간 차이를 현물환율로 나눈 것과 같아야 한다.", related: ["스왑레이트"] },
  { id: 118, term: "금본위제", definition: "금본위제란 각국의 통화가치를 순금의 일정한 중량으로 정해 놓고 금화의 자유로운 주조와 수출입을 허용하며 이를 지폐나 예금통화 등과 교환할 수 있도록 하는 제도이다. 금본위제는 전형적인 고정환율제도이다.", related: ["고정환율제도/자유변동환율제도"] },
  { id: 119, term: "금산분리", definition: "산업자본과 금융자본이 결합하는 것을 제한하는 원칙을 금산분리라고 한다. 산업자본이 금융자본을 지배하게 되면, 은행이 특정 기업의 사금고처럼 이용될 수 있어 시장의 공정한 경쟁을 저해하고 독과점을 초래할 수 있다.", related: [] },
  { id: 120, term: "금융EDI", definition: "EDI(Electronic Data Interchange)는 기업 상호 간에 접속된 컴퓨터를 이용하여 재화와 용역의 거래정보를 표준화된 양식으로 교환하여 상거래를 처리하는 시스템이다. 금융EDI는 여기에 은행이 개입하여 지급결제를 포함한 거래정보까지도 전자적으로 처리하는 시스템이다.", related: ["전자금융"] },
  { id: 121, term: "금융공황", definition: "금융공황(Banking Panic)은 일부 금융기관이 심각한 경영난에 빠졌을 때 예금인출사태(bank run)가 다른 금융기관에까지 급속하게 확산되어 금융시장 전체가 신용경색 사태에 직면하는 현상을 말한다.", related: ["뱅크런", "연방준비제도(FRS)"] },
  { id: 122, term: "금융불안지수(FSI)", definition: "금융불안지수(FSI; Financial Stress Index)는 금융불안 가능성을 속보성 있게 판단하는 지수이다. 한국은행이 매월 산출하고 있다. FSI가 12를 넘으면 주의 수준, 24를 넘으면 위험 수준 단계에 진입하였음을 의미한다.", related: ["금융취약성지수(FVI)"] },
  { id: 123, term: "금융사이클", definition: "경제주체의 위험추구 성향, 신용담보로 제공되는 실물자산의 가치변동 등이 상호작용하면서 나타나는 금융변수들의 종합적인 순환변동을 의미한다. 금융사이클의 평균주기는 24.5분기로 실물사이클(14.5분기)에 비해 더 긴 것으로 분석되었다.", related: [] },
  { id: 124, term: "금융상황지수(FCI)", definition: "금융상황지수(FCI; Financial Conditions Index)는 전반적인 금융여건의 완화 또는 긴축 여부를 판단하기 위한 지수이다. 장단기 시장금리가 낮아지고 주가가 상승하는 경우 금융상황이 완화된 것으로 해석된다.", related: [] },
  { id: 125, term: "금융시스템 상호연계성", definition: "특정 시점에서 시스템 리스크를 초래할 수 있는 핵심 요인인 상호연계성은 해당 금융업권(기관)이 영업활동 과정에서 여타 금융업권(기관)과 밀접하게 연결된 정도를 의미한다.", related: ["시스템 리스크"] },
  { id: 126, term: "금융시장인프라", definition: "금융시장인프라(FMI; Financial Market Infrastructure)는 금융 거래지급, 청산, 결제, 기록 등을 가능하게 하는 시스템과 기관들을 총칭하는 용어이다. FMI의 주요 구성요소는 지급시스템, 증권결제시스템, 중앙예탁기관(CSD), 중앙청산소(CCP)로 구분할 수 있다.", related: ["지급결제시스템", "증권결제시스템"] },
  { id: 127, term: "금융안정", definition: "금융회사들이 정상적인 자금중개기능을 수행하고, 금융시장 참가자들의 신뢰가 유지되는 가운데 금융인프라가 잘 구비되어 있어 금융시스템이 원활히 작동하는 상태를 의미한다. 한국은행은 2011년 9월 「한국은행법」 개정으로 금융안정 책무를 명시적으로 부여받았다.", related: ["시스템 리스크"] },
  { id: 128, term: "금융안정위원회(FSB)", definition: "기존 금융안정포럼(FSF)의 국제금융시장 안정 기능을 보다 강화하기 위하여 2009년 4월 금융안정위원회(FSB; Financial Stability Board)가 설립되었다. 현재 25개국의 금융당국과 10개 국제기구 대표가 회원으로 활동하고 있다.", related: [] },
  { id: 129, term: "금융연관비율(골드스미스비율)", definition: "금융연관비율(Financial Interrelations Ratio)은 한 나라의 금융자산 잔액을 유형자산(실물자산 또는 국부) 잔액으로 나눈 비율로 골드스미스(R.W.Goldsmith)가 사용하기 시작하였다.", related: [] },
  { id: 130, term: "금융의 증권화", definition: "금융의 증권화(Securitization)란 금융기관이 보유하고 있는 대출채권 등 유동성이 낮은 자산을 매매 가능한 유가증권 형태로 전환하는 자산유동화를 지칭한다. 모기지대출을 기초자산으로 유동화한 증권을 주택저당증권(MBS)이라 한다.", related: [] },
  { id: 131, term: "금융의 탈중개화", definition: "블록체인을 통한 송금, P2P대출처럼 금융중개기관을 거치지 않고 거래가 당사자 간에 직접 이뤄지는 현상을 탈중개화라고 한다. 이는 금융중개기관에 대한 수요를 감소시키는 반면, 금융서비스 공급자의 수를 증가시키는 방향으로 작용한다.", related: ["핀테크", "블록체인", "P2P대출"] },
  { id: 132, term: "금융의 탈집중화", definition: "금융의 탈집중화(Decentralization)는 분야별 금융시장에 새로 진입한 핀테크 업체들의 파괴적인 경쟁력 때문에 금융 분야별로 서비스가 더 세분화(unbundling)되는 현상을 말한다.", related: ["핀테크", "P2P대출", "블록체인"] },
  { id: 133, term: "금융이해력", definition: "금융이해력은 재무적 자원을 효과적으로 관리하고 생애 전반에 걸쳐 재정적 안정을 확보하기 위해 필요한 금융 지식, 기술, 태도 등을 포괄하는 능력을 의미한다. 금융 지식, 금융 행위, 금융 태도와 같은 요소들을 포괄한다.", related: [] },
  { id: 134, term: "금융제도", definition: "금융거래에 관한 체계와 규범을 총칭하는 개념으로 금융시장, 금융기관, 금융하부구조(infra-structure)로 구분된다. 금융시장은 간접금융시장과 주식, 채권 등 증권을 통해 자금의 수요자와 공급자 간에 직접적인 자금 이전이 이루어지는 직접금융시장으로 구분된다.", related: [] },
  { id: 135, term: "금융중개지원대출제도", definition: "한국은행의 금융중개지원대출제도는 은행의 중소기업에 대한 대출 확대를 유도하기 위해 은행별 중소기업 대출 취급실적에 비례하여 한국은행이 낮은 금리로 자금을 공급하는 대출제도를 말한다.", related: [] },
  { id: 136, term: "금융지주회사", definition: "금융지주회사(Financial Holding Company)는 지분 보유를 통해 은행, 증권, 보험, 자산관리 등의 금융업을 영위하는 자회사들을 소유하여 경영하는 모회사를 말한다. 우리나라에서는 2000년 10월 금융지주회사법이 제정되었다.", related: [] },
  { id: 137, term: "금융채", definition: "금융채는 은행, 금융투자회사, 리스회사, 신용카드회사 등 금융기관이 장기적으로 안정적인 자금을 조달하기 위하여 발행하는 채권을 말한다. 금융채 금리는 은행의 대출금리와도 관련이 있다.", related: ["자금조달비용지수(COFIX)"] },
  { id: 138, term: "금융취약성지수(FVI)", definition: "금융안정 상황을 판단하기 위해 금융시스템 내 잠재하고 있는 취약성(vulnerability)을 평가하고 이를 통해 중장기 금융안정 리스크를 측정하는 금융안정 관련 지수이다. 한국은행은 2021년 6월부터 금융취약성지수를 편제해오고 있다.", related: ["금융불안지수(FSI)"] },
  { id: 139, term: "금융통화위원회", definition: "금융통화위원회(Monetary Policy Board)는 통화신용정책 수립 및 한국은행 운영에 관한 최고 의사결정기구로서 7명의 위원으로 구성된다. 통화정책방향(기준금리 포함) 의결을 위한 정기회의는 매년 8회 개최된다.", related: ["한국은행"] },
  { id: 140, term: "금융 하부구조", definition: "지급결제시스템, 신용평가제도, 주식시장, 선물시장 등과 같이 금융거래가 원활하게 이루어질 수 있도록 지원하는 각종 제도적 장치 및 기관을 의미한다.", related: [] },
  { id: 141, term: "금전신탁", definition: "금전신탁이란 수탁자가 금전을 신탁재산으로 위탁받아 이를 대출, 채권 등 적절한 투자대상에 운용하여 얻은 이익을 수익자에게 금전 등의 형태로 되돌려 주는 제도이다. 금전신탁은 이익분배에 있어서 실적배당을 원칙으로 한다.", related: [] },
  { id: 142, term: "기념화폐", definition: "기념화폐는 국가적 행사, 역사적 사건, 중요한 인물 또는 국가유산 등을 기념하기 위해 특별히 발행되는 화폐로서 주로 수집 가치와 기념적 의미를 지니며 액면가보다 높은 가격에 판매되는 경우가 많다.", related: ["화폐 발행"] },
  { id: 143, term: "기대인플레이션", definition: "기대인플레이션은 향후 물가상승률에 대한 경제주체의 주관적인 전망을 나타내는 개념으로 물가안정을 추구하는 중앙은행이 관심을 기울이고 안정적으로 관리해야 하는 핵심지표 중 하나이다. 기대인플레이션은 임금협상, 가격설정, 투자결정 등 경제주체의 의사결정에 반영되면서 최종적으로 실제 인플레이션에 영향을 미친다.", related: ["인플레이션"] },
  { id: 144, term: "기본자본(Tier 1)", definition: "국제결제은행(BIS)의 기준에 따른 은행의 자기자본을 구성하는 요소로서, 예상외 손실이 발생할 경우 은행이 영업을 계속하면서 손실을 흡수할 수 있는 자본이다. 보통주자본(CET1)과 기타기본자본(AT1)으로 구성된다. 바젤 Ⅲ에서는 기본자본비율이 위험가중자산의 6.0% 이상이 되도록 규정하고 있다.", related: ["BIS 자기자본비율", "보통주자본"] },
  { id: 145, term: "기업간(B2B) 지급시스템", definition: "기업간(B2B) 지급시스템은 전자외상매출채권(전자채권)의 발행과 만기시 결제를 처리하는 시스템으로 2002년 3월 가동되었다. 채권의 만기일은 발행일로부터 3영업일 이후부터 180일 이내이다.", related: [] },
  { id: 146, term: "기업·개인간(B2C) 지급결제시스템", definition: "기업·개인간(B2C) 지급결제시스템은 인터넷쇼핑몰 등의 전자상거래에서 이루어지는 판매자 및 구매자간의 소액결제에 이용되는 지급결제시스템을 통칭하는 용어이다.", related: ["소액지급시스템"] },
  { id: 147, term: "기업경기실사지수(BSI)", definition: "기업경기실사지수(BSI; Business Survey Index)는 국내외 경기동향에 대한 기업가들의 판단, 예측, 계획의 변화 추이를 조사하여 작성되며, 경기분석 및 전망에 활용된다. BSI = [(긍정적 응답업체 수 - 부정적 응답업체 수)/전체 응답업체 수] × 100 + 100", related: ["경제심리지수", "소비자동향지수(CSI)"] },
  { id: 148, term: "기업공개", definition: "기업공개(IPO; Initial Public Offering)란 주식을 다수의 투자자들에게 분산 매각하는 것을 말한다. 주식회사가 신규 발행 주식을 다수의 투자자로부터 모집하거나 이미 발행된 주식을 일반에 분산 매출하고 증권거래소에 상장하여 거래되도록 하는 것이다.", related: ["모집"] },
  { id: 149, term: "기업분할(물적분할, 인적분할)", definition: "기업분할이란 회사의 특정사업부를 분할하여 새로운 회사를 설립하는 것을 의미한다. 인적분할은 존속회사의 주주들이 지분 비율에 따라 신설법인의 주식을 비례적으로 나누어 갖는 방식이다. 물적분할은 신설된 법인의 주식을 모회사가 전부 소유하는 방식이다.", related: [] },
  { id: 150, term: "기업심리지수(CBSI)", definition: "기업심리지수(CBSI; Composite Business Sentiment Index)는 기업경기실사지수(BSI)의 주요 지수를 이용하여 산출한 지표이다. CBSI는 100보다 클 경우 경제상황에 대한 기업들의 기대심리가 과거 평균보다 낙관적임을 나타낸다.", related: ["기업경기실사지수(BSI)"] },
  { id: 151, term: "기업어음(CP)", definition: "기업어음(CP; Commercial Paper)은 신용상태가 양호한 기업이 상거래와 관계없이 운전자금 등 단기자금을 조달하기 위하여 자기신용을 바탕으로 발행하는 융통어음을 의미한다. CP는 발행절차가 간편하고 통상 담보없이 신용으로 발행된다.", related: ["진성어음/융통어음"] },
  { id: 152, term: "기업회생절차", definition: "기업이 자력으로 회사를 꾸려가기 어려울 만큼 부채가 많을 때 법원에서 지정한 제3자가 자금을 비롯하여 기업활동 전반을 관리하는 것을 말한다. 재정적 어려움으로 파산에 직면하였으나 회생 가능성이 있는 기업의 경우에 기업에 대한 채권자, 주주, 기타 이해관계인의 이해를 조정하여 정리재건을 도모하는 제도이다.", related: [] },
  { id: 153, term: "기저효과", definition: "기저효과(Base Effect)는 경제지표 증가율을 해석할 때 기준시점과 비교시점의 상대적인 위치에 따라서 경제 상황에 대한 평가가 실제보다 위축되거나 부풀려지는 등의 왜곡이 일어나는 것을 말한다.", related: ["계절변동조정시계열"] },
  { id: 154, term: "기준금리", definition: "한국은행 금융통화위원회에서 결정하는 정책금리를 말한다. 한국은행과 금융기관 간에 환매조건부채권매매(RP)와 대기성 여수신 등의 자금거래를 할 때 기준으로 적용된다. 2008년 3월부터 정책금리의 실체를 '기준금리(Base Rate)'로 변경하였다.", related: ["환매조건부매매/RP/Repo"] },
  { id: 155, term: "기준순환일", definition: "기준순환일이란 경기변동 과정에서 국면전환이 이루어진 일자를 의미한다. 즉 경기가 확장국면에서 수축국면으로 전환하는 경기정점 또는 수축국면에서 확장국면으로 전환하는 경기저점의 구체적인 일자를 말한다.", related: ["경기", "경기종합지수"] },
  { id: 156, term: "기준환율", definition: "기준환율이란 일반적으로 '다른 외국 통화 환율 결정의 기준이 되는 특정 통화의 환율'을 의미한다. 우리나라의 경우 원/달러 환율이 기준환율이며 원/엔, 원/유로, 원/파운드 등 여타 각국 통화의 환율은 원/달러 환율과 각국 통화의 대미달러화 환율을 기초로 하여 자동적으로 산출(재정환율)된다.", related: ["재정환율"] },
  { id: 157, term: "기초가격", definition: "기초가격(Basic Price)은 생산자가격에서 부가가치세와 같은 생산물세를 제외하고 정부에서 주는 보조금을 더한 가격을 의미하는 것으로 순수하게 생산자(주로 기업)가 갖게 되는 몫을 말한다.", related: ["국내총생산(GDP)"] },
  { id: 158, term: "기축통화", definition: "기축통화란 여러 국가의 암묵적인 동의하에 국제거래에서 중심적인 역할을 하는 통화를 지칭한다. 2차 세계대전 이후에는 전 세계 외환거래 및 외환보유액의 상당 부분을 차지하는 미국 달러화가 기축통화로 인정받고 있다.", related: ["교환성 통화"] },
  { id: 159, term: "기타기본자본(Additional Tier 1)", definition: "기타기본자본(AT1; Additional Tier 1)은 바젤Ⅲ 자본규제에서 기본자본(Tier 1)을 구성하는 요소로서, 은행의 계속적인 영업을 전제로 손실흡수능력이 있다고 인정되는 자본을 의미하며 영구적 성격을 지닌 자본증권의 발행으로 인한 자본금·자본잉여금 등이다.", related: ["기본자본(Tier 1)"] },
  { id: 160, term: "기펜재", definition: "일반적으로 재화는 수요의 법칙에 따라 가격이 하락하면 수요량이 늘어난다. 그러나 예외적으로 재화의 가격이 하락할 때 수요량이 감소하는 현상을 관찰할 수 있다. 이렇게 가격이 하락할 경우 수요의 법칙에 위배되는 재화를 기펜재라고 부른다.", related: ["밴드웨건효과", "베블런효과"] },
  { id: 161, term: "기회비용", definition: "다양한 욕구의 대상들 가운데서 하나를 고를 수밖에 없을 때 포기한 선택의 욕구들로부터 예상되는 유·무형의 이익 중 최선의 이익을 기회비용(Opportunity Cost)이라고 한다. 자원의 희소성이 존재하는 한 기회비용은 반드시 발생하게 된다.", related: ["한계비용"] },
  { id: 162, term: "기후테크", definition: "기후테크(Climate Tech)는 기후 변화 문제를 해결하거나 완화하기 위한 기술을 말한다. 태양광 및 풍력 등 청정에너지 개발, 탄소 포집 및 저장, 전기차 및 수소차 등 친환경 이동수단 등 다양한 분야가 있다.", related: ["에너지 믹스", "녹색기후기금(GCF)"] },
  { id: 163, term: "긴급수입제한조치", definition: "긴급수입제한조치(Safeguard) 즉, 세이프가드란 특정 품목의 수입이 급증하여 국내 업체에 심각한 피해가 발생하거나 그럴 우려가 있을 경우, 수입국이 관세 인상이나 수입량 제한 등을 통해 수입품에 대한 규제를 할 수 있는 제도이다.", related: ["상계관세", "슈퍼301조"] },
  { id: 164, term: "긴축정책", definition: "경기과열 우려가 있는 경우 재정 또는 통화정책으로 각 경제주체들의 재화 및 서비스에 대한 수요를 위축시켜 지출을 줄이는 등 경기의 과열을 방지하려는 정책을 긴축정책(Contractionary Policy)이라고 한다.", related: ["경기조절정책", "재정정책", "통화정책"] },
  { id: 165, term: "꼬리위험", definition: "경제성장률이나 주가, 환율 등 시장가격변수 분포의 꼬리부분 이벤트가 발생할 위험을 꼬리위험(Tail Risk)이라고 한다. 양극단 꼬리부분에 해당하는 이벤트는 발생 가능성은 매우 낮지만 일단 발생하면 경제 전체에 지대한 영향을 줄 수 있는 위험이다.", related: [] },
  { id: 166, term: "낙수효과", definition: "정부가 경제정책으로 대기업과 고소득층의 소득과 부를 먼저 늘려주게 되면 이들의 소비와 투자 증가를 통해 전체 경제활동이 활발해지면서 결국에는 중소기업과 저소득층도 혜택을 볼 수 있다는 주장이다. 낙수효과(Trickle-Down Effect)는 분배보다는 성장과 효율성을 중시하는 논리에 근거한다.", related: ["분수효과"] },
  { id: 167, term: "낙인효과", definition: "어떤 사람이 사회적으로 바람직하지 못한 행위를 한 번 저지르고 나쁜 사람으로 낙인찍히면 그 사람에 대한 부정적 인식이 형성되고 이 인식은 쉽게 사라지지 않는다. 경제 분야에서도 한 번 부도를 일으킨 기업이나 국가의 경우 이후 건전성을 회복했다 하더라도 시장의 충분한 신뢰를 얻기 어려워진다.", related: [] },
  { id: 168, term: "난외거래", definition: "은행의 권리·의무가 확정되지 않아 재무상태표상(on-balance sheet) 자산·부채로 기록되지 않는 거래를 의미한다. 대표적인 난외(off-balance sheet)거래로는 채무보증, 계약이행보증, 신용장, 금리 및 외환 관련 파생상품거래의 신용리스크 상당액 등이 있다.", related: [] },
  { id: 169, term: "납부자자동이체", definition: "납부자자동이체(Standing Order)는 고객이 거래은행이 아닌 다른 은행에 대출원리금, 정기적금 등을 정기적으로 납부할 때 거래은행의 본인계좌에서 다른 은행으로 자동 이체시켜 주는 업무로서 1994년 4월부터 실시되었다.", related: ["지로(GIRO)", "출금이체"] },
  { id: 170, term: "내국신용장", definition: "국내 외국환은행이 수출업자의 의뢰에 따라 수출업자 앞 국제 신용장(Master L/C)을 담보로 하는 등의 방식으로 국내 제조업자 또는 공급업자 앞으로 발행하는 신용장을 말한다.", related: [] },
  { id: 171, term: "내부등급법", definition: "바젤 자본규제에서 감독당국의 승인을 받은 은행이 자산군별로 리스크 측정 요소를 자체 측정모형을 통해 추정하고 이를 내부등급법 산식에 대입하여 신용리스크에 대한 위험가중자산을 산출하는 방법을 말한다.", related: [] },
  { id: 172, term: "내부자금", definition: "기업이 투자 재원을 내부유보, 감가상각충당금 등에서 조달한 것을 내부자금이라고 한다. 금융기관 차입, 유가증권 발행, 해외차입 등을 통해 조달한 것을 외부자금이라고 한다.", related: ["외부자금"] },
  { id: 173, term: "노동생산성/노동생산성지수", definition: "노동자 1인이 일정 기간 동안 산출해 내는 생산량으로 정의된다. 노동생산성지수 = 산출량지수/노동투입량지수×100. 임금이 노동생산성보다 더 빠르게 상승하면 단위노동비용이 증가하기 때문에 기업은 제품가격의 상승 압력을 받게 된다.", related: ["단위노동비용"] },
  { id: 174, term: "노동시장 긴장도", definition: "노동 수요(기업의 일자리 수)와 노동 공급(일할 사람의 수)의 균형 정도를 나타내는 지표이다. 노동 수요가 공급에 비해 많은 경우 노동시장의 긴장도는 높아지며 임금 상승 압력도 높아진다.", related: ["구인배수", "실업률"] },
  { id: 175, term: "녹색GDP", definition: "녹색GDP(Green GDP)는 한 나라의 국내총생산(GDP)에서 생산활동 중 발생하는 자연자원의 감소나 환경피해 등의 손실액을 공제한 것으로 이해된다. 기존의 GDP가 생산활동 과정에서 발생하는 자원고갈, 환경오염 등으로 인한 부정적인 효과를 전혀 반영하지 못하는 데서 대안으로 나온 것이다.", related: [] },
  { id: 176, term: "녹색기후기금(GCF)", definition: "개발도상국의 온실가스 감축과 기후변화 대응을 지원하기 위하여 만들어진 UN 산하의 국제금융기구이다. 2013년 12월에 공식 출범하였으며 사무국은 한국의 인천 송도국제도시에 위치하고 있다.", related: [] },
  { id: 177, term: "뉴스심리지수(NSI)", definition: "뉴스심리지수(NSI; News Sentiment Index)는 경제분야 뉴스기사에 나타난 경제심리를 지수화한 것이다. 한국은행은 2022년 1월부터 뉴스심리지수를 개발하여 공표하고 있다. NSI는 100보다 크면 낙관적인 것으로, 100보다 작으면 비관적인 것으로 해석된다.", related: [] },
  { id: 178, term: "단기금융시장", definition: "단기금융시장(Money Market)은 금융기관, 기업 등 경제주체들이 단기적인 자금수급 불균형을 조절하기 위하여 통상 만기 1년 이내의 단기 금융상품을 거래하는 시장이다. 콜시장, 기업어음(CP)시장, 양도성예금증서(CD)시장 등이 있다.", related: ["장기금융시장(자본시장)"] },
  { id: 179, term: "단리/복리", definition: "단리(Simple Interest)는 원금에 대해서만 약정된 이율과 기간을 곱하여 이자를 산출하는 방식이다. 복리(Compound Interest)는 일정 기간마다 발생한 이자를 원금에 합산한 후 그 합산금액에 대한 이자를 다시 계산하는 방식이다. 복리에서는 72법칙이라는 것이 있는데 원리금이 두 배로 불어나는데 필요한 저축기간과 수익률의 곱이 72%만 되면 된다는 것이다.", related: [] },
  { id: 180, term: "단위노동비용", definition: "단위노동비용이란 산출물 한 단위를 생산하는데 소요되는 노동비용을 말한다. 단위노동비용 = 시간당 노동비용(임금) / 노동생산성. 임금의 상승 또는 노동생산성의 악화는 단위노동비용을 증가시킨다.", related: ["노동생산성"] },
  { id: 181, term: "단일금리방식/복수금리방식", definition: "복수금리(가격)방식은 각 낙찰자가 입찰시 제시한 금리(가격)를 발행금리(발행가격)로 하는 방식이며, 단일금리(단일가격)방식은 각 낙찰자가 입찰시 제시한 금리(가격) 중 최고금리(최저가격)를 발행금리(발행가격)로 하는 방식이다.", related: ["통화안정증권"] },
  { id: 182, term: "담보인정비율(LTV)", definition: "주택담보대출 취급 시 담보가치(주택가격) 대비 대출 취급 가능금액의 비율 (Loan-To-Value ratio)을 의미한다. 예를 들어 아파트 감정가격이 5억원이고 LTV가 70%이면 금융기관으로부터 3억 5천만원의 주택담보대출을 받을 수 있다.", related: ["총부채상환비율(DTI)", "총부채원리금상환비율(DSR)"] },
  { id: 183, term: "당일결제/익일결제/익익일결제", definition: "당일결제(value today)는 거래계약일에 외환의 인수·인도와 관련 대금의 결제가 이루어지는 현물환 거래방식이다. 익영업일결제는 거래계약 후 1영업일, 익익영업일결제는 거래계약 후 2영업일에 결제가 이루어지는 거래방식이다.", related: ["선물환거래"] },
  { id: 184, term: "대기성 여수신제도", definition: "대기성 여수신제도(Standing Facilities)는 금리 중심 통화정책 운영방식 하에서 단기시장금리의 과도한 변동을 억제하기 위한 정책수단이다. 대기성 여신금리는 단기시장금리의 상한기능을, 대기성 수신금리는 하한기능을 수행한다.", related: [] },
  { id: 185, term: "대량지급", definition: "대량지급(Direct Credit)은 급여, 연금, 배당금 등과 같이 일시 또는 정기적으로 발생하는 다수의 고객을 대상으로 동시에 이루어지는 거래를 위하여 공공기관이나 대기업 등 이용기관의 예금계좌에서 다수의 수취인 예금계좌로 자금을 이체하는 업무이다.", related: ["지로(GIRO)", "입금이체"] },
  { id: 186, term: "대손충당금적립비율", definition: "거래상대방의 부도 등으로 회수가 어려워 손실이 발생할 수 있는 채권에 대해 미리 비용으로 처리해서 사내에 유보해둔 자금을 대손충당금이라고 한다. 대손충당금 적립비율 = 은행이 적립한 대손충당금 / 고정이하여신 금액", related: ["고정이하여신비율"] },
  { id: 187, term: "대안정기", definition: "1980년대 중반 이후 2007년 금융위기 이전까지 약 20년간 일본을 제외한 주요 선진국에서 산출량, 인플레이션 등 거시변수의 변동성이 크게 감소하면서 경제가 안정을 누린 기간을 지칭한다. 2002년 전미경제연구소(NBER) 연례 세미나에서 처음 사용한 용어이다.", related: ["골디락스경제"] },
  { id: 188, term: "대외의존도/수출입의존도/무역의존도", definition: "대외의존도란 개방경제체제 하의 국민경제에서 국외부문과의 거래가 차지하는 크기를 측정하는 지표이다. 구체적으로 대외의존도는 국민소득에서 수출과 수입이 차지하는 비중으로 계산된다.", related: ["국내총생산(GDP)", "국민총소득(GNI)"] },
  { id: 189, term: "대외지급준비자산", definition: "대외지급준비자산이란 한 나라의 통화 당국이 경제에 큰 영향을 미치지 않고 언제든지 대외 지급에 충당할 수 있도록 보유하고 있는 준비자산(금, SDR, IMF position 및 보유 외화)을 말한다.", related: ["외환보유액", "IMF 포지션"] },
  { id: 190, term: "대체비용리스크", definition: "미래 특정일자에 종료될 거래의 상대방이 거래를 취소하거나 파산할 경우, 결제일 전에 결제가 이행되지 못할 가능성을 감안하여 다른 거래로 대체하는 과정에서 발생할 비용리스크를 의미한다.", related: ["외환결제리스크", "증권결제리스크"] },
  { id: 191, term: "대체재", definition: "비슷한 만족을 얻을 수 있어 서로 경쟁 관계에 있는 재화 또는 서비스를 말한다. 두 제품 중 어느 한 제품의 가격상승이 다른 재화의 수요증가를 초래할 때 이 두 제품은 서로 대체관계에 있다고 한다.", related: ["보완재"] },
  { id: 192, term: "대출금 출자전환", definition: "금융기관이 차주기업에 대한 대출채권을 동 기업의 주식과 교환하는 것으로서 금융기관의 차주기업에 대한 관계가 채권자에서 주주로 변하게 된다. 기업은 부채비율 하락과 원리금 상환부담 감소로 경영정상화를 도모할 수 있다.", related: [] },
  { id: 197, term: "독점/과점", definition: "독점(Monopoly)은 완전경쟁의 정반대인 시장 형태로 어느 기업이 시장의 유일한 공급자로 그 기업이 공급하는 상품에 밀접한 대체재가 존재하지 않는 경우를 말한다. 독점이 생기는 이유는 생산요소 독점, 생산기술 문제, 정부 규제 등으로 시장에 진입장벽이 존재하기 때문이다. 한편, 시장에 유사하거나 동일한 상품을 공급하는 공급자가 소수에 불과할 때에는 과점(Oligopoly)이라고 부른다. 과점시장은 기업들의 의사결정 과정이 서로 연결된 상호의존 관계를 가지는 특징이 있다. 우리나라에서도 '독점규제 및 공정거래에 관한 법률'을 통하여 불공정한 거래행위를 규제하여 경제 전반의 공정하고 자유로운 경쟁을 촉진하고 있다.", related: ["죄수의 딜레마", "카르텔"] },
  { id: 198, term: "동남아시아국가연합(ASEAN)", definition: "동남아시아의 지역협력기구로서 아세안(ASEAN; Association of South-East Asian Nations)이라고도 부른다. 동남아시아 지역협력의 촉진, 외국의 간섭 배제 및 역내 국가의 평화와 안정 수호, 경제·사회·문화·기술 등 각 분야에서의 상호원조를 설립목적으로 하고 있다. 1967년 8월 창설 당시 5개국이었으나 현재는 총 10개국으로 늘어났으며, 2015년 12월 아세안경제공동체를 출범시킴으로써 단일시장 구축을 추진하고 있다.", related: ["동남아시아국가연합+한·중·일(ASEAN+3)", "치앙마이 이니셔티브 다자화(CMIM)"] },
  { id: 199, term: "동남아시아국가연합+한·중·일(ASEAN+3)", definition: "한국, 중국, 일본 및 ASEAN 10개국이 합의하여 1999년 출범한 국제회의체이다. 동아시아 외환위기를 배경으로 위기 극복 및 재발 방지를 위한 통화·금융 협력을 증진하는 데 목적을 두고 있다. 2010년 3월에는 기존 양자간 스왑계약체제를 다자간 스왑계약체제로 전환하는 CMI 다자화 협정(CMIM)의 체결이 이루어졌다.", related: ["치앙마이 이니셔티브(CMI)", "치앙마이 이니셔티브 다자화(CMIM)"] },
  { id: 200, term: "동남아시아중앙은행기구(SEACEN)", definition: "회원 간 정보 및 의견 교환, 공동 관심 분야에 대한 조사연구 및 연수 활동을 주요 기능으로 하는 동남아 중앙은행들의 협력체로서 1966년 2월 동남아 7개국 주도로 출범하였다. 2025년 6월 현재 19개국 중앙은행이 회원으로 있으며, 한국은행은 1990년 1월에 가입하였다.", related: ["국제통화기금(IMF)", "아시아개발은행(ADB)"] },
  { id: 201, term: "동아시아 외환위기", definition: "1997년 태국을 시작으로 인도네시아, 말레이시아, 필리핀, 한국 등 동아시아 국가들에서 발생한 외환위기. 태국 바트화 가치가 고정환율제도 포기의 영향으로 폭락하고 그 여파로 동아시아 국가들은 외환시장 마비, 급격한 자본유출 등으로 큰 어려움을 겪었다. 한국은 1997년 12월 IMF에 구제금융을 신청하여 IMF 195억 달러, 세계은행 70억 달러, ADB 37억 달러를 지원받았다. 이들 국가는 1999년에는 대체로 위기상황에서 벗어났다.", related: ["국제통화기금(IMF)", "아시아개발은행(ADB)"] },
  { id: 202, term: "동아시아 태평양중앙은행기구(EMEAP)", definition: "EMEAP(Executives' Meeting of East Asia and Pacific Central Banks)는 동아시아, 태평양 지역 내 중앙은행 간의 협력을 증진하고 회원국의 금융·경제에 관한 정보교환을 위해 1991년 설립된 중앙은행 간 협력체이다. 회원은 한국, 호주, 중국, 홍콩, 인도네시아, 일본, 말레이시아, 뉴질랜드, 필리핀, 싱가포르, 태국 등 11개국의 중앙은행이다. 한국은행은 창설회원으로 모든 회의에 적극 참여하고 있다.", related: [] },
  { id: 203, term: "동일인 신용공여한도제", definition: "특정인에 대한 금융기관의 여신 편중을 억제하기 위한 규제. 은행법 제35조는 동일인 및 동일차주에 대한 신용공여가 각각 해당 은행 자기자본의 20% 및 25%를 초과할 수 없도록 규율하고 있다. 또한 자기자본의 10% 초과 거액신용공여의 합계가 자기자본의 500%를 초과하지 못하도록 규정하고 있다.", related: ["거액익스포저 규제", "익스포저"] },
  { id: 204, term: "동태적 대손충당금 제도", definition: "발생손실 기준 대손충당금 회계기준 하에서 나타나는 은행 대출의 경기순응성을 완화하기 위해 2000년 7월 스페인을 비롯하여 다수 남미 국가에서 도입된 거시건전성 정책이다. 경기 호황기에 일반충당금을 늘리고 불황기에 줄이는 방식으로 운영되어, 호황기 신용팽창을 억제하고 불황기 신용공급 위축을 완화할 수 있다.", related: ["경기순응성"] },
  { id: 205, term: "동행종합지수", definition: "경기종합지수의 하나로, 경기순환과 함께 변동하는 광공업생산지수, 서비스업생산지수, 건설기성액, 소매판매액지수, 내수출하지수, 수입액, 비농림어업취업지수 등 7개 개별지표를 종합하여 만들어진다. 현재의 경기상황 판단에는 동행종합지수에서 추세변동을 제거한 순환변동치를 주로 사용한다.", related: ["경기종합지수", "후행종합지수"] },
  { id: 206, term: "듀레이션", definition: "채권에서 발생하는 현금흐름의 가중평균만기로 투자자금의 평균회수기간을 의미한다. 채권의 만기가 길수록, 표면금리가 낮을수록, 만기수익률이 낮을수록 듀레이션은 길어진다. 듀레이션은 채권가격의 이자율탄력성을 나타내는 척도이자 중요한 리스크 관리수단으로 활용된다.", related: [] },
  { id: 207, term: "등록발행", definition: "채권을 실물발행하지 않고 등록기관이 관리하는 채권등록부에 채권자의 권리내역을 등록함으로써 채권자의 법적 권리를 보장하는 것. 현재 대부분의 채권은 실물발행 없이 등록발행되고 있다. 국채·통화안정증권은 한국은행이, 금융채·회사채 등은 한국예탁결제원이 각각 등록업무를 담당한다.", related: [] },
  { id: 208, term: "디레버리징", definition: "부채를 축소하는 것. 가계나 기업 등 경제주체의 재무상태표에서 부채의 비중을 낮추는 것을 의미한다. 2008년 글로벌 금융위기 이후 세계 각국에서 나타난 경제 전체의 디레버리징은 거시경제 전반에 심대한 영향을 미쳤으며, 민간부문의 디레버리징을 상쇄하는 과정에서 정부부채가 증가하는 현상이 많은 나라에서 관찰되었다.", related: ["레버리지 효과"] },
  { id: 209, term: "디스인플레이션", definition: "물가수준이 지속적으로 높아지고 있으나 물가상승률은 둔화되는 현상. 단기간에 그치면 크게 걱정할 일은 아니지만, 지속될 경우 가계와 기업이 소비와 투자를 미룸으로써 수요 위축과 경기침체가 초래될 수 있다.", related: ["디플레이션", "통화정책"] },
  { id: 210, term: "디커플링/커플링", definition: "디커플링(탈동조화)이란 어떤 나라나 지역의 경제가 인접한 다른 국가나 전반적인 세계 경제의 흐름과 다른 모습을 보이는 현상. 반대로 한 나라 또는 지역의 경제가 인접한 다른 국가나 세계 경제 흐름과 유사한 흐름을 보이는 것을 커플링(동조화)이라 한다.", related: [] },
  { id: 211, term: "디플레이션", definition: "물가가 지속적으로 하락하는 현상. 생산물의 과잉공급, 자산거품의 붕괴, 과도한 통화 긴축정책 등이 원인이다. 실질금리 상승에 따른 총수요 감소, 실질임금 상승에 따른 고용 및 생산 감소, 소비지출 연기에 따른 경제활동 위축 등의 문제를 일으킬 수 있다.", related: ["인플레이션", "피셔효과"] },
  { id: 212, term: "래퍼곡선", definition: "미국의 경제학자 래퍼(A. Laffer)가 제시한 조세수입과 세율 간의 관계를 나타낸 곡선. 세율이 0%에서 100%로 증가할 때 조세수입은 상승하다가 정점에 이른 후 다시 하강하는 '역 U자 모양의 곡선'이 된다. 미국 레이건 정권의 감세정책을 뒷받침한 이론적 근거로 이용되었다.", related: ["조세부담률"] },
  { id: 213, term: "레그테크", definition: "금융업 등 산업 전반에 걸쳐 혁신 IT와 규제를 결합하여 규제관련 요구사항 및 절차를 효율적으로 처리하는 기술 또는 회사. RegTech(Regulatory Technology)의 약자로, 금융서비스 산업의 새 영역이자 일종의 핀테크이다.", related: ["핀테크", "빅데이터"] },
  { id: 214, term: "레버리지비율/단순기본자본비율", definition: "레버리지비율은 '[기본자본(Tier 1) / 총익스포저(난외자산 포함)] × 100'으로 정의된다. 자기자본비율 규제의 문제점을 보완하는 지표로, 바젤위원회는 2015년 1월부터 공시를 의무화하였으며 은행들은 2018년 1월부터 최저 레버리지비율(3%)을 준수해야 한다.", related: ["기본자본(Tier 1)", "디레버리징"] },
  { id: 215, term: "레버리지 효과", definition: "실제 가격변동률보다 몇 배 많은 투자수익률이 발생하는 현상. 투자액의 일부가 부채로 조달될 때 나타나며, 레버리지 비율이 높을수록 손익이 확대된다. 레버리지는 수익과 손실을 모두 확대시키는 '양날의 칼'에 비유된다.", related: ["디레버리징"] },
  { id: 216, term: "로렌츠곡선", definition: "1905년 미국의 통계학자 로렌츠(M. Lorenz)가 소득의 불평등 정도를 측정하기 위해 제안한 것으로, 인구의 누적비율을 가로축에 소득의 누적점유율을 세로축에 놓고 이들의 관계를 그림으로 표시한 곡선. 로렌츠 곡선이 대각선에 가까울수록 분배가 평등하다. 지니계수는 이 곡선을 이용하여 소득분배를 정량화한 지표이다.", related: ["지니계수"] },
  { id: 217, term: "로보어드바이저", definition: "로봇(robot)과 자문가(advisor)의 합성어로, 인공지능 알고리즘과 빅데이터를 활용하여 투자자의 성향·리스크 선호도·목표수익률 등을 분석하고 온라인 자산관리서비스를 제공하는 것. 기존 자산관리서비스보다 낮은 최소투자금액과 수수료로 일반 개인도 쉽게 접근할 수 있다.", related: ["빅데이터", "상장지수펀드(ETF)"] },
  { id: 218, term: "리디노미네이션", definition: "현재의 화폐단위로 표시된 가격, 예금·채권·채무 등 일체의 금액을 법정비율에 따라 일률적으로 조정하여 새로운 화폐단위로 표기 및 호칭하는 것. 주로 지속적인 인플레이션으로 인해 숫자가 많아져 계산 불편을 해소할 목적으로 시행된다. 우리나라는 1953년, 1962년 두 차례 통화조치를 시행한 바 있다.", related: [] },
  { id: 219, term: "리쇼어링/니어쇼어링/프렌드쇼어링", definition: "리쇼어링(Reshoring)은 해외에 생산기지를 둔 기업이 다시 본국으로 돌아오는 현상. 니어쇼어링(Nearshoring)은 지리적으로 가까운 국가로, 프렌드쇼어링(Friend-Shoring)은 정치적·외교적으로 우호적인 국가로 업무나 생산활동을 이전하는 전략.", related: ["글로벌가치사슬(GVC)"] },
  { id: 220, term: "리스크 온(Risk On)/오프(Off)", definition: "리스크 온은 투자자들이 위험 자산(주식, 암호화폐 등)에 적극적으로 투자하는 상황, 리스크 오프는 안전 자산(채권, 금 등)으로 투자 자금을 이동하는 상황을 의미한다. 경제 성장 기대감, 금리 인상 가능성, 지정학적 리스크 등이 이를 결정한다.", related: ["안전자산/위험자산"] },
  { id: 221, term: "마러라고 합의", definition: "트럼프 미국 대통령의 플로리다 별장 '마러라고(Mar-a-Lago)'의 이름을 딴 경제 정책 구상으로 1985년의 플라자 합의를 현대적으로 재해석한 전략. 미국의 무역적자 해소와 제조업 부흥을 위해 달러화의 인위적 평가절하를 추진하는 것이 핵심이다.", related: [] },
  { id: 222, term: "마샬의 k", definition: "경제 전체의 명목소득 대비 통화량 보유 비율. 거래수량설 방정식 MV=PY에서 M=kPY의 관계가 도출되며, 마샬의 k는 화폐유통속도의 역수와 동일하다. 한 나라의 경제규모 대비 통화공급의 적정 수준을 판단하는 지표로도 사용된다.", related: [] },
  { id: 223, term: "마스트리히트조약", definition: "유럽공동체(EC)의 12개 회원국이 1992년 2월 7일 네덜란드 마스트리히트에서 서명하고, 1993년 11월 1일부터 발효된 조약. 유럽중앙은행 창설 및 단일통화 사용의 경제통화동맹(EMU) 달성, 공동방위정책 형성 등을 핵심내용으로 하며, 이에 따라 유럽공동체(EC)는 유럽연합(EU)으로 변경되었다.", related: ["유럽연합(EU)", "유럽중앙은행(ECB)"] },
  { id: 224, term: "마진콜", definition: "금융 투자에서 투자자의 계좌 가치가 일정 수준 이하로 떨어졌을 때 증권사나 브로커가 추가 증거금(margin)을 요구하는 것. 추가 증거금을 납입하지 못할 경우 증권사에서 강제로 자산을 매도할 수도 있어 투자자는 큰 손실을 볼 수 있다.", related: ["유지 증거금", "강제 청산"] },
  { id: 225, term: "마찰적 실업", definition: "새로운 일자리를 탐색하거나 이직하는 과정에서 일시적으로 발생하는 실업. 경기침체로 인한 비자발적 실업이 아닌 자발적 실업이며, 경기가 좋은 경우에도 발생할 수 있다. 일자리 정보 서비스를 개선하여 구인자와 구직자 간 원활한 정보교환이 이뤄지도록 하는 것이 중요하다.", related: ["자발적 실업"] },
  { id: 226, term: "만기수익률", definition: "채권을 만기까지 보유했을 때 얻을 수 있는 예상 연간 수익률.", related: ["이표채"] },
  { id: 227, term: "매매보호 서비스(Escrow)", definition: "전자상거래 시 신뢰할 수 있는 중립적인 제3자가 중개역할을 하여 상거래가 원활히 이루어질 수 있도록 하는 서비스. 소비자가 대금을 제3자에게 보관하고, 구매자가 물품 확인 후 제3자가 판매자에게 대금을 송금하는 절차로 이루어진다. 인터넷 사기 피해를 줄여주는 효과가 있다.", related: [] },
  { id: 228, term: "매몰비용", definition: "이미 지급되어 회수할 수 없는 비용. 어떤 선택을 할 때 선택에 따른 편익은 극대화하고 비용은 최소화하되 이미 지출된 매몰비용은 무시해야 한다. 이미 투입한 비용이 아까워 경제성 없는 프로젝트를 지속하는 것을 매몰비용 오류(Sunk Cost Fallacy)라 한다.", related: ["기회비용"] },
  { id: 229, term: "매입외환/환가료", definition: "매입외환은 외국환은행이 고객으로부터 매입한 수출환어음 등 외국환으로 표시된 자산. 환가료는 외국환은행이 수출환어음 등을 매입하는 경우 원화 대금 지급 시점과 외화자금 수취 시점 사이에 은행이 부담하는 이자와 환차손 등을 보전받기 위해 고객에게 부과하는 수수료.", related: ["내국신용장"] },
  { id: 230, term: "매출액영업이익률", definition: "기업의 주된 영업활동의 효율성을 측정하는 지표로 영업손익을 매출액으로 나누어 산출한다. 이 비율은 높을수록 좋으나 표준치가 없으므로 경쟁관계에 있는 기업이나 동종 업종의 평균치 또는 과거실적과 비교해서 판단한다.", related: [] },
  { id: 231, term: "머니마켓펀드(MMF)", definition: "고객의 일시적인 여유자금을 금리위험과 신용위험이 적은 국공채, 어음 등에 운용하고 동 운용에서 발생하는 수익을 배당하는 펀드. 대표적인 단기금융상품으로, 운용자산의 가중평균 잔존만기가 60일 이내로 제한된다. 유동성 측면에서 익일 설정 및 익일 환매가 이루어진다.", related: ["단기금융시장", "펀드"] },
  { id: 232, term: "명목GDP목표제", definition: "명목GDP가 사전에 정한 목표수준을 따라가는 것을 목표로 하는 통화정책 운영체제. 글로벌 금융위기 이후 물가안정목표제의 대안으로 일부 학계를 중심으로 제시되었으나, 물가안정에 대한 신뢰성 확보가 어렵고 현실 적합성이 크게 떨어진다는 한계로 현재 실제로 채택한 사례는 없다.", related: ["물가안정목표제"] },
  { id: 233, term: "명목GDP/실질GDP", definition: "명목GDP는 최종생산물의 가치를 그 생산물이 생산된 기간의 가격으로 계산한 것. 실질GDP는 기준년도의 가격으로 측정한 것으로, 경제성장·경기변동 등 전반적인 경제활동 흐름을 분석하는 데 이용된다. 명목GDP는 특정 시점의 국가간 비교에 활용된다.", related: ["연쇄가중법", "경제성장률"] },
  { id: 234, term: "명목금리/실질금리", definition: "명목금리는 물가변동을 고려하지 않고 표면상 표현된 금리. 실질금리는 물가상승률을 고려한 금리로, 명목금리에서 물가상승률을 빼서 계산한다. 피셔효과란 명목금리는 실질금리에 예상 물가상승률을 더해서 결정된다는 이론이다.", related: ["피셔효과"] },
  { id: 235, term: "명목소득/실질소득", definition: "명목소득은 소득이 발생할 당시의 가격으로 측정된 소득. 실질소득은 통화가치의 변동을 감안하여 명목소득을 기준시점에 맞춰 조정한 것. 경제지표를 정확히 이해하기 위해서는 명목과 실질의 개념으로 구분해서 살펴보아야 한다.", related: ["실질임금"] },
  { id: 236, term: "모기지대출", definition: "주택이나 부동산을 담보로 하여 은행 등 금융기관에서 장기간 자금을 빌리는 대출.", related: ["주택저당증권(MBS)", "자산유동화"] },
  { id: 237, term: "모바일뱅킹", definition: "고객이 휴대전화 등 모바일기기를 이용하여 무선인터넷을 통하여 금융기관에 접속하여 이용할 수 있는 금융서비스. 예금조회, 자금이체 등 기본서비스 외에 대출, 환율조회 등 다양한 서비스를 제공한다.", related: ["인터넷뱅킹"] },
  { id: 238, term: "모집", definition: "자본시장에서 불특정 다수로부터 동일한 조건으로 유가증권 취득의 청약을 권유하는 것. 불특정 다수로부터 공개모집하는 공모(public offering)와 50인 미만을 대상으로 하는 사모(private offering)가 있다.", related: ["간접금융/직접금융"] },
  { id: 239, term: "무디스", definition: "1909년 미국의 John Moody가 창업한 신용평가기관. S&P, Fitch와 함께 세계 3대 국제신용평가기관으로 인정받고 있다. Aaa(최우량)에서 C(최저)까지의 신용등급을 부여하며, 평가 경향이 보수적인 것으로 알려져 있다.", related: ["스탠더드&푸어스"] },
  { id: 240, term: "무역지수", definition: "수출액 또는 수입액의 변동요인을 가격요인과 물량요인으로 나누어 분석하기 위해 한국은행에서 작성하는 지수. 수출입금액지수, 수출입물가지수, 수출입물량지수가 있으며, 이를 이용하여 한 나라의 교역조건을 측정한다.", related: ["순상품교역조건지수"] },
  { id: 241, term: "무위험지표금리(KOFR)", definition: "Korea Overnight Financing Repo Rate의 약자로, 국채·통안증권을 담보로 하는 익일물 RP금리를 사용하여 산출한 우리나라의 무위험지표금리(RFR). LIBOR 금리 조작사건 등을 계기로 개발된 대체지표금리로, 2021년 11월 26일부터 정식 공시를 시작하였다.", related: ["지표금리", "환매조건부채권(RP)"] },
  { id: 242, term: "물가안정목표제", definition: "중앙은행이 명시적인 중간목표 없이 일정기간 동안 달성해야 할 물가상승률 목표치를 미리 제시하고 이에 맞추어 통화정책을 운영하는 방식. 1990년 뉴질랜드에서 처음 도입되었으며, 우리나라는 1998년부터 시행하고 있다.", related: ["통화정책 운영체제"] },
  { id: 243, term: "물가지수", definition: "물가의 변화를 한 눈에 알아볼 수 있도록 기준연도의 물가수준을 100으로 놓고 비교되는 다른 시점의 물가를 지수 형태로 나타낸 것. 우리나라의 대표적인 물가지수로 생산자물가지수, 소비자물가지수, 수출입물가지수 등이 있다.", related: ["근원인플레이션"] },
  { id: 244, term: "뮤추얼펀드", definition: "투자자들이 자금을 모아 투자 회사를 설립해 주식이나 채권, 파생상품 등에 투자한 후 그 운용수익을 주주들에게 배당금 형태로 나누어주는 투자신탁의 하나. 전문 펀드매니저를 통해 운용하는 간접투자 방식이다.", related: ["펀드"] },
  { id: 245, term: "미국·멕시코·캐나다협정(USMCA)", definition: "1994년 체결된 북미자유협정(NAFTA)을 대체하는 협정으로 2020년 7월 1일 공식 발효. 원산지규정 및 노동규정을 강화하여 미국 내 제조업 보호와 고임금 일자리 창출을 도모하며, 디지털 무역 관련 규정을 추가하였다. 협정의 존속기간은 16년이다.", related: [] },
  { id: 246, term: "미달러화지수", definition: "미국 달러화의 가치를 주요 6개국 통화(유로, 엔, 파운드, 캐나다 달러, 스웨덴 크로나, 스위스 프랑) 대비 미달러화 환율을 가중평균하여 측정하는 지수. 1973년 브레튼우즈체제 붕괴 이후 도입되었으며 기준점은 1973년 3월(100)이다.", related: ["브레튼우즈체제"] },
  { id: 247, term: "미달러화페그제도", definition: "자국 통화의 미국 달러화에 대한 환율을 고정시켜 둔 채 기타 통화에 대한 환율은 미국 달러화 대 기타통화의 환율변동에 따라 자동으로 결정되게 하는 환율제도. 환율변동에 대한 불확실성이 제거되지만 자국 경제 상황을 환율이 적절히 반영하지 못하는 문제가 있다.", related: ["고정환율제도/자유변동환율제도"] },
  { id: 248, term: "미발행화폐", definition: "한국은행이 보유하고 있는 은행권과 주화 중 폐기하기로 결정한 것을 제외한 모든 은행권과 주화. 한국은행은 미발행화폐를 본부와 각 지역본부에 분산하여 보관하고 있다.", related: [] },
  { id: 249, term: "미분양주택", definition: "주택사업자가 분양 공고를 내고 입주자를 모집하였으나 정해진 일정 내에 청약이 이루어지지 않은 주택. 주택경기를 파악할 수 있는 지표 중 하나로, 주택이 준공된 이후에도 분양계약이 체결되지 않는 경우 준공 후 미분양주택으로 분류한다.", related: [] },
  { id: 250, term: "바이오인증", definition: "개인을 식별하거나 인증하기 위해 각 개인마다 구별해서 측정할 수 있는 고유 생체정보를 자동화된 장치에 보관하고 금융거래시 이를 이용해 본인임을 인증하는 기술. 지문·홍채·정맥·안면 등 신체적 특성과 음성·서명 등 행동적 특성을 활용한다.", related: [] },
  { id: 251, term: "바젤은행감독위원회(BCBS)", definition: "1974년말 G10 국가 중앙은행 총재회의의 결의로 설립된 은행감독 국제협력 기구. 은행 건전성을 규율하기 위한 국제기준 등을 제정하고 은행감독 관련 사안들에 대한 국제협력의 장을 제공한다. 2024년 현재 28개국 45개 중앙은행 및 은행감독기관이 회원으로 참여하고 있다.", related: [] },
  { id: 252, term: "반대매매", definition: "만기까지 대출금을 갚지 못하거나 담보가치가 일정 비율 이하로 떨어지면 증권사가 주식을 강제로 처분하는 것. 신용매매, 스탁론 서비스, 미수 거래 계좌를 이용해 주식을 매입했을 경우 발생할 수 있다.", related: ["신용거래", "담보비율"] },
  { id: 253, term: "발행시장", definition: "주식이나 채권 등의 유가증권을 신규로 발행하는 시장(Primary Market). 발행주체(기업, 정부 등)가 유가증권을 최초로 발행하여 투자자에게 제공하고 자금을 조달하는 일련의 과정이 발생한다.", related: ["유통시장"] },
  { id: 254, term: "발행어음", definition: "금융회사가 투자자로부터 자금을 조달하기 위해 발행하는 만기 1년 이내의 어음. 발행어음을 매입한 고객은 만기에 약정된 이자를 원금과 함께 받는다. 신용도가 높은 금융회사에게만 발행이 허용된다.", related: [] },
  { id: 255, term: "발행중지화폐/유통정지화폐", definition: "발행중지화폐는 발행은 중단되지만 화폐로서의 강제통용력이 있고 지급결제수단으로 사용 가능한 화폐. 유통정지화폐는 화폐 발행을 중단할 뿐만 아니라 시중에서의 사용도 정지되어 강제통용력이 상실된 화폐.", related: [] },
  { id: 256, term: "방카슈랑스", definition: "은행을 의미하는 프랑스어 Banque와 보험을 의미하는 Assurance의 합성어. 은행과 보험회사가 서로 연결되어 일반 개인에게 폭넓은 금융서비스를 제공하는 시스템. 우리나라는 2003년 8월부터 시행되었다.", related: ["범위의 경제"] },
  { id: 257, term: "배당할인모형", definition: "주식투자에 따라 발생하는 미래의 현금흐름을 적절한 할인율로 할인하여 현재가치로 전환함으로써 주식의 현재가치를 평가하는 모형. Gordon의 정률성장배당할인모형에 따르면 현재 주식의 가치(P0)=D1/(r-g)이다.", related: ["배당금", "할인율"] },
  { id: 258, term: "밴드웨건효과", definition: "소비자가 대중적으로 유행하는 정보를 쫓아 상품을 구매하는 현상. 유행에 동조함으로써 타인들과의 관계에서 소외되지 않으려는 비이성적인 심리에서 비롯된다. 주식시장이나 부동산시장의 거품형성과 붕괴현상도 이로 설명할 수 있다.", related: ["베블런효과"] },
  { id: 259, term: "뱅크런", definition: "은행의 대규모 예금인출사태. 금융시장 상황이 불안하거나 은행의 건전성에 문제가 발생하면 예금자들이 저축한 돈을 급격히 인출함으로써 은행이 지급 자금 부족으로 패닉 상태에 빠지는 현상. 예금보험공사는 1억원까지 예금을 보호한다.", related: ["예금보험제도"] },
  { id: 260, term: "범위의 경제", definition: "개별 기업이 한 종류의 제품만을 생산하는 경우보다 여러 제품을 같이 생산하면서 평균 생산비용이 적게 드는 현상(Economies of Scope). 은행이 보험 상품을 판매하는 방카슈랑스가 대표적인 예이다.", related: ["규모의 경제"] },
  { id: 261, term: "법정화폐", definition: "법률에 의해 인정되는 공적 지불수단의 성격을 지닌 화폐. 우리나라의 경우 한국은행법 제48조에서 한국은행권이 모든 거래에 무제한 통용된다고 규정하고 있다.", related: [] },
  { id: 262, term: "베버리지곡선", definition: "노동 공급(실업률) 및 수요(빈일자리율) 간 관계를 나타내는 곡선. 통상 실업률이 높아지면 빈일자리율이 줄어들고, 반대의 경우 빈일자리율이 늘어나는 관계가 있다. 노동시장 내 마찰적 요인 증가로 매칭 효율성이 낮아질 경우 곡선 자체가 오른쪽으로 이동한다.", related: [] },
  { id: 263, term: "베블런효과", definition: "가격이 상승하면 수요량이 감소하는 수요 법칙에 반하여 사치재, 명품 등이 가격이 비쌀수록 소비가 증가하는 과시 욕구 반영 소비현상. 베블런은 이 현상을 처음으로 관찰한 학자의 이름이다.", related: ["기펜재", "밴드웨건효과"] },
  { id: 264, term: "변동금리", definition: "시장금리를 반영하여 일정 주기별로 약정금리가 변하는 금리. 고정금리는 최초 약정한 금리가 만기까지 그대로 유지되는 금리. 앞으로 시장금리가 상승할 것으로 예상되면 고정금리가, 하락할 것으로 예상되면 변동금리가 유리하다.", related: ["고정금리", "자금조달비용지수(COFIX)"] },
  { id: 265, term: "변동금리부채권(FRN)", definition: "지급이자율이 시장실세금리에 연동하여 이자지급기간마다 변동되는 채권. 금융시장의 불확실성 확대로 금리에 대한 장기예측이 어려울 때 금리변동 위험을 최소화하기 위해 발행한다. 기준금리에 가산금리를 더하는 방식으로 지급이자율이 결정된다.", related: [] },
  { id: 266, term: "보복소비", definition: "상당 기간 소비가 억제된 후 반작용으로 소비가 급격하게 늘어나는 것. 코로나19로 억눌렸던 소비 욕구가 보복하듯 한꺼번에 분출하는 현상을 지칭하기 위해 널리 쓰이게 되었다.", related: [] },
  { id: 267, term: "보완자본(Tier 2)", definition: "국제결제은행(BIS) 기준에 따른 은행 자기자본을 구성하는 요소로, 기본자본에 비해 손실흡수능력이 떨어지지만 은행 파산 시 예금자를 포함한 일반채권자에 앞서 손실을 흡수할 수 있는 자기자본.", related: ["BIS 자기자본비율", "기본자본(Tier 1)"] },
  { id: 268, term: "보완재", definition: "두 가지 이상의 재화가 함께 사용됨으로써 효용을 얻을 수 있는 재화. 한 재화의 가격이 하락하면 다른 재화의 수요가 증가하는 관계. 승용차와 휘발유, 컴퓨터와 소프트웨어가 대표적인 예이다.", related: ["대체재"] },
  { id: 269, term: "보통주자본(CET1)", definition: "바젤Ⅲ 자본규제에서 기본자본(Tier 1)을 구성하는 핵심 요소로서 손실흡수능력이 가장 높은 자본. 보통주 발행으로 인한 자본금·이익잉여금 등으로 구성되며 바젤Ⅲ에서는 위험가중자산의 4.5% 이상이 되도록 규정하고 있다.", related: ["기본자본(Tier 1)"] },
  { id: 270, term: "보편관세", definition: "특정 품목이나 국가에 국한되지 않고 모든 수입품에 일률적으로 적용되는 관세. 차별관세는 출처 국가나 품목에 따라 서로 다른 관세율을 적용하며, 상호관세는 상대국의 불공정한 관세에 대응하여 동일하거나 유사한 방식으로 부과하는 관세이다.", related: [] },
  { id: 271, term: "보호무역주의", definition: "국가간 무역을 제한하는 경제정책. 관세 부과, 수입할당, 보조금 지급 등이 주요 수단. 수입으로 경쟁이 유발되는 산업의 생산·고용을 보호하는 것이 목적이나, 소비자에게 물가 상승과 같은 부정적 영향을 미친다.", related: [] },
  { id: 272, term: "복수통화바스켓제도", definition: "자국과 교역 비중이 큰 복수국가의 통화를 선택하여 통화군(바스켓)을 구성하고 바스켓 통화들의 가치 변동에 따라 자국통화의 환율에 반영하는 환율제도. 우리나라는 1980년 2월부터 복수통화바스켓제도를 시행하다가 1990년 3월 시장평균환율제도로 이행하였다.", related: ["고정환율제도/자유변동환율제도"] },
  { id: 273, term: "본드포워드거래", definition: "두 당사자가 미래의 일정 시점에 정해진 가격으로 채권을 매수하거나 매도하기로 약속하는 금융 계약. 주로 금리 리스크 헤지, 투자 전략 수립 등을 목적으로 사용되며 보험사들이 자산 듀레이션을 늘리거나 금리 변동 위험을 헤지하기 위한 수단으로 활용한다.", related: [] },
  { id: 274, term: "본원소득", definition: "제도단위가 생산과정에 참여하거나 생산활동에 제공된 자산을 소유함에 따라 발생하는 소득(국민순소득). 본원소득 = 피용자보수 + 영업잉여 + 순생산 및 수입세 + 순수취재산소득.", related: ["영업잉여", "피용자보수"] },
  { id: 275, term: "본원소득수지", definition: "급료 및 임금 수지와 투자소득수지로 구분된다. 급료 및 임금 수지는 외국인 근로자에게 지급되거나 내국인 해외근로자가 수취하는 금액의 차이, 투자소득수지는 대외 금융자산과 부채의 보유에 의해 발생하는 배당금과 이자 등의 차이.", related: ["본원소득"] },
  { id: 276, term: "본원통화", definition: "통화량의 원천이 되는 통화(RB; Reserve Base). 민간보유현금과 금융기관의 지급준비금의 합계. 중앙은행이 증권을 매입하거나 금융기관에 대출을 실시하면 본원통화가 증가한다. 통화량 = 통화승수 × 본원통화.", related: ["통화승수"] },
  { id: 277, term: "볼커룰", definition: "2008년 글로벌 금융위기를 계기로 2010년 미국 의회가 제정한 금융개혁법의 핵심 조항. 상업은행의 자기계정투자(proprietary trading)를 금지하고 헤지펀드 및 사모펀드에 대한 투자를 제한하는 것이 골자이다. 전 연방준비제도이사회 의장 폴 볼커(Paul Volcker)의 제안이 반영되어 볼커룰이라 부른다.", related: ["도드-프랭크법"] },
  { id: 278, term: "부가가치", definition: "일정 기간 동안에 경제활동주체가 생산활동에 참여하여 새로이 창출한 가치. 총산출에서 중간투입을 차감하여 구할 수 있다. 국민경제 부가가치 총액이 국내총생산(GDP)이다.", related: ["총산출", "글로벌가치사슬(GVC)"] },
  { id: 279, term: "부가가치기준 무역(TiVA)", definition: "국가간 거래를 재화와 서비스의 각 생산 단계에서 창출된 부가가치를 기준으로 파악하는 경제통계. 글로벌 공급망이 복잡해지면서 전통적 무역통계의 한계를 보완하기 위해 개발되었으며, 국가별 경쟁력 분석, 산업정책 수립 등에 중요한 기초자료이다.", related: ["산업연관표"] },
  { id: 280, term: "부가가치유발계수/부가가치계수", definition: "최종수요가 한 단위 발생할 경우 국민경제 전체에서 직·간접으로 유발되는 부가가치 단위를 보여주는 계수. 예를 들어 농림수산품의 부가가치계수가 0.9라는 것은 동 수요 1단위 발생 시 0.9단위의 부가가치가 유발됨을 의미한다.", related: ["생산유발효과"] },
  { id: 281, term: "부동화/무권화", definition: "부동화(Immobilization)는 실물증권을 중앙예탁기관에 집중 보관하여 계좌대체 방식으로 처리함으로써 실물인도의 필요성을 제거하는 것. 무권화(Dematerialization)는 실물증권을 발행하지 않고 장부상 전자기록 형태로만 존재하게 하는 것.", related: ["중앙예탁기관"] },
  { id: 282, term: "부실채권(NPL)", definition: "금융기관의 대출이나 지급보증 중 차주의 재정상황 악화로 회수가 어려운 자산. Non-Performing Loan의 약자로, 원리금 상환이 3개월 이상 연체된 고정 이하 등급의 대출이 해당된다.", related: [] },
  { id: 283, term: "부채담보부증권(CDO)", definition: "회사채나 대출채권 등으로 구성된 pool을 기초자산으로 하여 다양한 신용등급으로 발행된 선·후순위 채권. 2007년 서브프라임 모기지 사태로 CDO 채권 가격이 폭락하면서 주요 금융회사들이 큰 손실을 입고 글로벌 금융위기로 이어졌다.", related: [] },
  { id: 284, term: "부채비율", definition: "부채를 자기자본으로 나눈 비율로 대표적인 안정성 지표. 이 비율이 낮을수록 재무구조가 건전하다고 판단. 부채비율이 높은 기업은 경기나 금리변동에 취약하여 현금흐름 악화 시 이자 부담이 커진다.", related: [] },
  { id: 285, term: "분리결제", definition: "증권매매거래 결제시 증권인도와 대금지급이 동시에 이루어지지 않고 개별적으로 이루어지는 방식(Free of Payment). 증권인도와 대금지급 간에 시차가 발생하므로 결제리스크가 발생할 수 있다.", related: ["증권대금동시결제(DVP)"] },
  { id: 286, term: "분산원장기술", definition: "거래정보가 기록된 원장을 특정 기관의 중앙 서버가 아닌 공유(P2P) 네트워크에 분산하여 다수의 참가자가 공동으로 기록·관리하는 기술(DLT). 비트코인·이더리움 등 가상자산의 기반 기술로 개발되었으나 현재 다양한 금융서비스에 활용 방안을 모색 중이다.", related: ["블록체인", "비트코인"] },
  { id: 287, term: "분수효과", definition: "정부가 저소득층과 중산층의 소득을 먼저 늘려주면 이들의 소비 확대가 생산과 투자로 이어지면서 전체 경제활동이 되살아나고 고소득층의 소득도 늘어날 수 있다는 주장. 분배보다 성장에 중점을 두는 낙수효과와 상반되는 개념이다.", related: ["낙수효과"] },
  { id: 288, term: "분절화", definition: "경제활동이나 시장이 작은 부분으로 나뉘어 서로 독립되거나 상호작용이 적어진 현상(Fragmentation). 미·중 무역갈등 심화, 주요국의 보호무역정책 경향 등으로 최근 분절화 경향이 확대되고 있다.", related: ["글로벌가치사슬(GVC)"] },
  { id: 289, term: "불완전경쟁시장", definition: "완전경쟁 요건이 충족되기 어려워 독점시장, 과점시장, 독점적 경쟁시장과 같은 형태가 나타나는 시장. 하나의 공급자가 가격을 결정하는 독점시장, 소수 공급자가 경쟁하는 과점시장, 다수의 공급자가 특화된 상품을 공급하는 독점적 경쟁시장으로 구분된다.", related: ["독점/과점"] },
  { id: 290, term: "불태화정책", definition: "해외부문으로부터의 외화유입으로 인해 본원통화가 증가하고 그 결과로 금리나 물가가 목표와 다르게 변동할 우려가 발생할 경우, 중앙은행이 공개시장 조작이나 지급준비율 조정 등을 통해 본원통화의 증가를 상쇄시키는 정책(Sterilization Policy).", related: ["외환시장"] },
  { id: 291, term: "브레튼우즈체제", definition: "1944년 미국 뉴햄프셔주 브레튼우즈에서 44개 연합국 대표들이 체결한 협정에 따라 발족한 국제통화체제. 미달러화를 기축통화로 하는 금환본위제도와 조정가능 고정환율제도를 핵심으로 하며, 1971년 미국이 달러화 금태환을 정지하면서 사실상 붕괴되었다.", related: ["국제통화기금(IMF)", "금본위제"] },
  { id: 292, term: "브렉시트(Brexit)", definition: "영국(Britain)과 탈퇴(Exit)의 합성어로 영국의 유럽연합(EU) 탈퇴를 뜻한다. 2016년 국민투표에서 51.9% 찬성으로 결정되었으며, 2020년 12월 말 공식적인 탈퇴 절차가 완료되었다.", related: ["유럽연합(EU)"] },
  { id: 293, term: "브릭스(BRICS)", definition: "브라질, 러시아, 인도, 중국, 남아프리카공화국 등 5개국의 영문 앞 글자를 따서 만든 용어. 2024년 1월 이집트, 에티오피아, 이란, 아랍에미레이트가, 2025년 1월 인도네시아가 정식 회원국으로 가입하면서 규모가 확대되었다.", related: [] },
  { id: 294, term: "브릿지론", definition: "개인이나 기업이 장기 자금조달 이전에 일시적으로 소요되는 비용을 충당하기 위해 단기 자금조달 수단으로 이용하는 것. 일반적으로 6개월~1년 만기 단기대출이며 본 PF대출에 비해 금리가 높다.", related: [] },
  { id: 295, term: "블록체인", definition: "일정 시간 동안 발생한 모든 거래정보를 블록 단위로 기록하여 모든 구성원들에게 전송하고, 유효성이 확보될 경우 기존의 블록에 추가 연결(chain)하여 보관하는 알고리즘. 탈중앙화와 탈중개화가 이루어지므로 비트코인 등 가상자산의 기반이 된다.", related: ["분산원장기술", "비트코인"] },
  { id: 296, term: "비관측경제(NOE)", definition: "GDP 추계에 이용되는 기초자료와 행정자료에 누락된 경제활동. 지하경제(조세 회피를 위해 은밀하게 이루어지는 활동), 불법생산(마약, 성매매 등), 소규모 기업·자영업자에 대한 미흡한 기초통계 등에 의해 발생한다.", related: ["국내총생산(GDP)"] },
  { id: 297, term: "비교우위", definition: "특정 국가나 경제주체가 다른 주체에 비해 상대적으로 더 적은 기회비용으로 어떤 재화나 서비스를 생산할 수 있는 능력. 리카르도(D. Ricardo)가 제시한 이론으로 각국이 비교우위를 가진 상품 생산에 특화하고 교역함으로써 상호 이익을 극대화할 수 있다.", related: ["현시비교우위지수(RCA)"] },
  { id: 298, term: "비용인상 인플레이션", definition: "노동, 자본, 원자재 등 투입요소 비용의 상승에 의해 물가가 지속적으로 오르게 되는 현상(Cost-Push Inflation). 1970년대 2차례의 오일쇼크로 인한 인플레이션이 대표적인 예이다.", related: ["수요견인 인플레이션"] },
  { id: 299, term: "비트코인", definition: "가상통화이자 디지털 지급시스템 전자 토큰 형태의 가상자산. 사토시 나카모토가 만든 것으로 알려져 있고 2009년 개방형 소프트웨어로 배포되었다. 총량은 2100만개이며 2140년경 모두 채굴될 것으로 전망된다.", related: ["가상자산", "블록체인"] },
  { id: 300, term: "빅데이터", definition: "복잡하고 다양한 대규모 데이터세트 자체는 물론 이 데이터로부터 정보를 추출하고 결과를 분석하여 더 큰 가치를 창출하는 기술. 대량(volume), 초고속(velocity), 고다양성(variety)의 특성을 지닌다.", related: ["로보어드바이저"] },
  { id: 301, term: "사전담보제", definition: "지급결제시스템의 참가자로 하여금 여타 시스템 참가자들 모두에 대한 순채무를 결제하기에 충분한 담보를 사전에 제공토록 하여 결제불이행 발생 시 결제의 종료를 보장하는 제도. 예치 담보로는 중앙은행 예치금이나 국채 등 유동성이 높은 증권이 주로 이용된다.", related: ["결제리스크", "차액결제시스템"] },
  { id: 302, term: "사전적 정책방향 제시(Forward Guidance)", definition: "향후 통화정책 방향에 대해 중앙은행이 명시적으로 시그널을 전달하는 것. 글로벌 금융위기 이후 정책금리의 추가 인하가 어렵고 경제여건의 불확실성이 높은 상황에서 주요국 중앙은행이 적극적으로 활용하면서 비전통적 통화정책의 일종으로 분류된다.", related: ["양적완화정책", "통화정책 커뮤니케이션"] },
  { id: 303, term: "4차 산업혁명", definition: "AI, 빅데이터, IoT, 블록체인 등의 정보통신기술이 산업과 사회 전반에 가져온 근본적이고 혁신적인 변화. 2016년 세계경제포럼(WEF)에서 클라우스 슈밥이 처음 사용한 용어로, 초연결성과 초지능으로 폭넓은 파급효과를 내는 '초연결지능 혁명'으로 볼 수 있다.", related: ["빅데이터"] },
  { id: 304, term: "사회보장제도", definition: "개인이 어떠한 불행을 당하더라도 국가가 최소한의 인간다운 생활을 보장할 수 있도록 하는 제도. 사회보험(산재보험, 국민연금, 고용보험, 건강보험), 공공부조(기초생활보장), 사회복지서비스(아동·노인·장애인 복지)로 구성된다.", related: ["사회보험", "상대적 빈곤율"] },
  { id: 305, term: "사회보험", definition: "보험방식을 통해 발생 가능한 각종 사회적 위험에 대처함으로써 국민의 생활, 건강, 소득 등을 보장하는 제도. 산업재해보험, 건강보험, 국민연금, 고용보험으로 구분된다. 보험료는 국가, 기업 및 개인이 분담하되 소득 수준에 비례하여 산정된다.", related: ["사회보장제도"] },
  { id: 306, term: "산업연관표(I/O Tables)", definition: "일정 기간 동안 국민경제 내에서 발생하는 재화와 서비스의 생산 및 처분과 관련된 모든 거래 내역을 기록한 종합적인 통계표. 1930년대 레온티에프 교수가 처음으로 작성 발표하였다. 우리나라에서는 한국은행이 1960년 산업연관표를 처음 작성한 이후 2006년부터 매년 작성하여 공표하고 있다.", related: ["생산유발효과"] },
  { id: 307, term: "삼불원칙", definition: "고정환율 유지, 자본의 자유로운 이동, 통화정책의 독립성 세 가지 정책목표를 동시에 만족시키는 것은 불가능하다는 원칙(Impossible Trinity, Trilemma). 고정환율제도하에서는 자본이동을 제약할 수밖에 없고, 자유변동환율제도하에서는 환율 변동을 용인해야 한다.", related: ["고정환율제도/자유변동환율제도"] },
  { id: 308, term: "상계관세", definition: "수출국이 수출기업에 보조금을 지급하여 지나치게 낮은 가격을 책정할 경우 수입국이 이로 인한 경쟁력 저하를 상쇄하기 위해 부과하는 관세(Countervailing Duties). 수입국 산업의 경쟁력을 유지하기 위한 일종의 차별관세라 할 수 있다.", related: ["긴급수입제한조치"] },
  { id: 309, term: "상대적 빈곤율", definition: "처분가능소득이 중위소득의 50%를 밑도는 계층이 전체 인구에서 차지하는 비율. 우리나라는 2022년 기준 14.9%를 기록하였다. 은퇴연령인구(66세 이상)는 48.2%로 매우 높은 수준이다. 소득이 최저생계비 미만인 가구의 비율을 절대적 빈곤율이라 한다.", related: ["지니계수", "사회보장제도"] },
  { id: 310, term: "상시감시제도/상시감시전담데스크", definition: "감독당국이 평상시 은행의 영업실적 및 재무상태에 관한 보고서를 징구·분석하는 등 전반적인 은행의 경영상황을 파악하기 위한 감독수단. 미국에서 문제은행의 조기식별 수단으로 발달된 제도로, 금융감독원은 금융기관별로 상시감시전담데스크를 설치·운영하고 있다.", related: [] },
  { id: 311, term: "상장지수펀드(ETF)", definition: "주식, 채권, 통화, 원자재 등의 가격지수를 추종하는 인덱스펀드의 지분을 거래소에 상장하여 일반주식처럼 거래하도록 한 금융상품. 최초의 ETF는 1993년 1월 뉴욕증권거래소에서 매매가 시작되었다. 일반 펀드와 달리 개인 주식거래계좌를 통해 손쉽게 거래할 수 있으며 거래비용이 낮다.", related: [] },
  { id: 312, term: "상품공동기금(CFC)", definition: "1차산품의 수급 안정을 위한 국제협력 증진과 국제상품협정 체결 촉진을 목적으로 1989년 7월 설립된 국제기구. 우리나라는 1989년 7월 설립과 함께 가입하였다.", related: ["세계무역기구(WTO)"] },
  { id: 313, term: "상품수지", definition: "거주자와 비거주자 간의 상품 수출입 거래를 계상한 것으로, 경상수지의 한 부분. 수출이 수입보다 많으면 흑자, 반대면 적자. 무역수지와 달리 상품수지는 소유권이전 기준으로 작성되며 수출과 수입 모두 FOB가격으로 평가한다.", related: ["경상수지"] },
  { id: 314, term: "상호관세", definition: "특정 상대국이 자국 제품에 대해 과도하거나 불공정한 관세를 부과할 경우 이에 대해 동일하거나 유사한 방식으로 관세를 부과하는 것(Reciprocal Tariff). 보복관세(retaliatory tariff)라고도 불린다.", related: ["보편관세"] },
  { id: 315, term: "생산세", definition: "국민계정체계(SNA)에서 조세를 종전 간접세에 해당하는 생산세와 소득·부 등에 대한 경상세, 자본세로 분류한 것. 생산세는 생산물세(제조·판매·이전 시 무과되는 조세)와 기타생산세(생산에 이용된 토지·고정자산·노동 등에 부과되는 조세)로 분류된다.", related: [] },
  { id: 316, term: "생산유발효과", definition: "최종수요의 변화가 생산에 미치는 영향. 자동차 수출 1대 증가 시 엔진, 타이어 등 수많은 중간재 생산이 필요하듯이, 한 산업의 생산은 관련 없어 보이는 많은 산업에까지 영향을 준다. 생산유발계수가 클수록 국내 생산에 미치는 영향이 크다.", related: ["고용유발효과/취업유발효과"] },
  { id: 317, term: "생산자물가지수(PPI)", definition: "국내생산자가 국내시장에 공급하는 상품과 서비스의 평균적인 가격변동을 측정하기 위하여 작성되는 물가지수. 포괄범위가 넓어 전반적인 수급 동향이 반영된 일반목적지수로서의 성격을 갖는다. 1910년부터 한국은행에서 작성하고 있다.", related: ["소비자물가지수(CPI)"] },
  { id: 318, term: "생산자제품재고지수", definition: "생산자가 보유하고 있는 완제품 재고의 변동을 파악하기 위한 것으로서 월말 재고수준을 나타내는 경기후행지표. 재고수준의 변동은 단기적인 경기순환을 나타내는 중요한 지표로 인식된다.", related: ["경기종합지수"] },
  { id: 319, term: "생산자제품출하지수", definition: "생산자의 판매활동과 광업, 제조업 제품의 출하 동향을 나타내는 지표. 내수용만 집계한 내수출하지수는 현재의 경기상황이 잘 반영되어 경기동행종합지수의 구성 지표로 활용된다.", related: ["경기종합지수"] },
  { id: 320, term: "생산확산지수", definition: "전반적인 생산 확산의 정도를 측정하는 경제지표. 지수가 50 이상이면 전월 대비 증가업종의 수가 감소업종의 수보다 많아 확산도 측면에서 본 생산경기가 확장국면에 있음을 의미한다.", related: ["경기종합지수"] },
  { id: 321, term: "생성형 인공지능(AI)", definition: "텍스트, 이미지, 음악, 코드 등 새로운 콘텐츠를 생성하는 AI 기술로 GPT, DALL-E, Sora 등이 대표적이다. 2020년대 들어 생성형 AI가 발전하면서 AI 붐이 형성되었다. 교육, 의료, 마케팅 등 다양한 분야에서 활용되고 있으나 허위정보 생산, 저작권 문제 등의 과제도 낳고 있다.", related: ["빅데이터"] },
  { id: 322, term: "생활물가지수", definition: "일상생활에서 구입 빈도가 높고 지출비중이 높아 가격변동을 민감하게 느끼는 생활필수품을 대상으로 작성한 지수. 통계청은 일반소비자들이 자주 구입하는 품목과 기본생필품을 중심으로 144개 품목(쌀, 달걀, 배추, 소주 등)을 선정하여 작성하고 있다.", related: ["물가지수", "소비자물가지수(CPI)"] },
  { id: 323, term: "서비스수지", definition: "외국과의 서비스거래 결과 벌어들인 돈과 지급한 돈의 차이. 가공, 운송, 여행, 건설, 보험, 금융, 통신, 지식재산권 등의 항목으로 이루어진다. 상품수지, 본원소득수지, 이전소득수지와 함께 경상수지를 구성한다.", related: ["경상수지"] },
  { id: 324, term: "서킷브레이커", definition: "주식시장에서 주가의 급등락 시 주식거래를 일시 정지시켜 시장에 미치는 충격을 완화하기 위한 '매매거래중단 제도'. 우리나라에는 1998년 12월 도입되었으며 2015년 개정 이후 1단계(8% 하락, 20분 중단), 2단계(15% 하락, 20분 중단), 3단계(20% 하락, 장종료)로 동작한다.", related: [] },
  { id: 325, term: "서학개미", definition: "해외, 주로 미국 주식에 직접 투자하는 한국 개인투자자를 일컫는 신조어. '서학'은 서양(=미국), '개미'는 소액 개인투자자를 비유한 표현이다. 서학개미의 활발한 해외 투자는 달러화 수요를 증가시켜 환율상승 요인으로 작용한다.", related: [] },
  { id: 326, term: "선물거래", definition: "공인된 거래소에서 품질, 규격 등이 표준화된 상품의 매매계약을 체결하고 일정기간이 경과한 후에 상품의 인수도와 결제가 이루어지는 거래(Futures Transactions). 곡물, 귀금속, 원유 등 일반상품과 통화, 채권, 주식 등 금융상품이 선물거래 대상이 된다.", related: ["옵션", "스왑"] },
  { id: 327, term: "선물환거래", definition: "계약일로부터 통상 2영업일 경과 후 특정일에 외환의 인수도와 결제가 이루어지는 거래. 주로 환리스크를 헤지하기 위한 목적으로 이용된다. 차액결제선물환(NDF)은 만기시점에 실물의 인수도 없이 차액만을 정산하는 방식이다.", related: ["차액결제선물환(NDF) 거래"] },
  { id: 328, term: "선물환포지션비율 규제", definition: "국내은행과 외국은행 지점의 선물환포지션을 자기자본의 일정 비율 이내로 제한하는 규제로 2010년 10월부터 시행된 제도. 2024년 12월 20일부터 국내은행 75%, 외국은행 지점 375%로 상향되었다. 외환건전성 관리의 핵심 정책수단으로 사용된다.", related: [] },
  { id: 329, term: "선불카드/선불전자지급수단", definition: "이용고객이 일정금액을 저장한 카드를 구입하여 상품구매 또는 서비스 이용시마다 대금이 자동으로 차감 지급되도록 한 카드. IC카드형은 주로 교통부문에, 네트워크형은 사이버쇼핑몰 등의 대금결제에 주로 사용된다.", related: ["지급수단", "전자화폐"] },
  { id: 330, term: "선행종합지수", definition: "실제 경기순환에 앞서 변동하는 개별지표를 가공·종합하여 만든 지수로 향후 경기변동의 단기 예측에 이용된다. 경기종합지수는 선행종합지수, 동행종합지수, 후행종합지수 3개가 작성된다.", related: ["경기종합지수", "후행종합지수"] },
  { id: 331, term: "성장기여도", definition: "특정 경제부문이 전체 경제성장에 어느 정도 기여했는가를 보여주는 지표. 부문별 성장기여율의 합은 100이 되며, 부문별 성장기여도의 합은 전체 성장률과 같게 된다. 예를 들어 GDP에서 제조업, 건설업, 서비스업 등 어떤 산업이 경제성장에 가장 큰 기여를 했는지 알 수 있다.", related: ["국내총생산(GDP)", "연쇄가중법"] },
  { id: 332, term: "세계경제포럼(다보스포럼)", definition: "저명한 기업인, 경제학자, 언론인, 정치인들이 모여 세계 경제를 개선하기 위한 과제를 토론하고 연구하는 회의체. 1971년 클라우스 슈바브 교수에 의해 창설되어 매년 1~2월경 스위스 다보스에서 연차총회가 개최되기 때문에 다보스포럼이라고도 불린다.", related: [] },
  { id: 333, term: "세계국채지수(WGBI)", definition: "영국의 FTSE 러셀이 발표하고 있는 주요국 국채로 구성된 국채지수. 세계 3대 채권지수 중 하나로, 2025년 7월 말 현재 25개국 국채를 포함하고 있다. 한국 국채는 2026년 4월부터 지수에 편입되기 시작하여 2026년 11월에 최종 편입 완료가 예정되어 있다.", related: [] },
  { id: 334, term: "세계무역기구(WTO)", definition: "국제무역 확대, 회원국 간의 통상분쟁 해결, 세계교역 연구를 위해 1995년 1월 1일 출범한 국제기구. 본부는 스위스 제네바에 있다. 준사법적 권한과 구속력을 행사할 수 있는 기능을 갖추고 있다. 2025년 9월 현재 회원국은 166개국이다.", related: [] },
  { id: 335, term: "세계은행(World Bank)", definition: "IBRD와 IDA를 합쳐 부르는 명칭. IBRD는 1945년 12월 개발도상국의 경제개발을 위한 장기개발자금 지원을 목적으로 설립되었다. IDA는 1960년 9월 저소득 회원국의 경제개발 촉진 및 생활수준 향상을 위한 자금 지원을 목적으로 발족하였다. 우리나라는 IBRD에 1955년, IDA에 1961년 가입하였다.", related: ["국제통화기금(IMF)"] },
  { id: 336, term: "소득5분위배율", definition: "소득 상위 20%(5분위) 계층의 평균소득을 소득 하위 20%(1분위) 계층의 평균소득으로 나눈 값. 값이 커질수록 고소득층과 저소득층 간의 소득분배가 악화하였음을 의미한다.", related: ["상대적 빈곤율", "지니계수"] },
  { id: 337, term: "소득교역조건지수", definition: "순상품교역조건지수에 수출물량지수를 곱하여 산출하는 것으로, 수출 총액으로 수입할 수 있는 상품의 양이 기준시점 대비 얼마나 증가하였는지를 의미한다. 순상품교역조건지수가 가격변동만을 고려하는 단점을 보완해 준다.", related: ["순상품교역조건지수"] },
  { id: 338, term: "소득대체율", definition: "은퇴 후 받는 연금수령액이 은퇴 전 소득에 대해 어느 정도 수준인지를 나타내는 용어. 너무 낮으면 연금제도의 유용성이 낮고, 너무 높으면 제도의 지속가능성에 문제가 생기는 아이러니가 있다.", related: ["사회보장제도", "국민연금"] },
  { id: 339, term: "소매판매", definition: "최종 소비자인 개인이나 가계를 대상으로 이루어지는 재화의 판매. 내수 경기의 흐름을 판단하는 데 중요한 역할을 한다. 소매판매액지수는 대형마트, 백화점, 편의점, 온라인 쇼핑몰 등 다양한 유통 채널을 조사하여 작성된다.", related: [] },
  { id: 340, term: "소비의 비가역성", definition: "상대소득가설에 따르면 현재소득이 과거의 최고 소득수준에 비해 작아지더라도 소비자는 소비를 소득감소에 비례하여 줄이지 않고 이보다 작은 폭으로 줄이게 되는 현상. 이로 인해 발생하는 톱니효과(Ratchet effect)는 단기적으로 소득이 변동할 경우 평균소비성향이 낮아지는 행태를 설명한다.", related: ["한계소비성향"] },
  { id: 341, term: "소비자동향지수(CSI)", definition: "소비자의 경기나 생활형편 등에 대한 주관적인 판단과 전망을 설문조사를 통해 지수화한 것. 한국은행이 매월 전국 2,500여 가구를 대상으로 19개 항목을 조사한다. 지수는 0~200 범위로, 100보다 크면 경제상황을 긍정적으로 보는 소비자가 더 많음을 의미한다.", related: ["경제심리지수", "기업경기실사지수(BSI)"] },
  { id: 342, term: "소비자물가지수(CPI)", definition: "일반 가구가 소비생활을 유지하기 위하여 구입하는 각종 상품과 서비스의 가격변동을 종합적으로 파악하기 위하여 작성되는 물가지표. 통계청에서 작성하며 2025년 현재 458여개 품목을 대상으로 한다. 소비자의 구매력과 생계비 측정에 사용되며 임금인상의 기초자료로 널리 이용된다.", related: ["생산자물가지수(PPI)", "인플레이션"] },
  { id: 343, term: "소비자심리지수", definition: "소비자를 대상으로 경기에 대한 판단이나 전망 등을 조사하여 지수화한 경제심리지표. 한국은행은 2005년 1/4분기부터 CCSI를 작성하여 발표하고 있다. 지수의 기준치는 100이며 100을 초과하면 현재 경기를 과거 평균 수준보다 좋아진 것으로 평가하고 있음을 의미한다.", related: ["경제심리지수", "기업경기실사지수(BSI)"] },
  { id: 344, term: "소액지급시스템", definition: "주로 기업이나 개인의 소액거래를 처리하는 지급시스템(Retail Payment System). 우리나라의 소액지급시스템은 금융결제원이 운영하고 있으며 어음교환시스템, 지로시스템, 금융공동망 등이 있다.", related: ["거액지급시스템", "지급결제시스템"] },
  { id: 345, term: "소프트랜딩/하드랜딩", definition: "소프트랜딩(연착륙)은 높은 성장세를 보이는 호황기 경제가 큰 충격 없이 점진적으로 둔화되어 안정되는 것. 하드랜딩(경착륙)은 갑작스러운 정책 변경이나 외부 충격으로 고성장 경제가 급격하게 침체 상태로 빠지는 것을 의미한다.", related: [] },
  { id: 346, term: "소형모듈원자로(SMR)", definition: "기존 대형 원전보다 출력 규모를 줄이고, 공장에서 모듈 단위로 제작한 뒤 현장에서 조립·설치하는 방식의 원자력 발전소. 일반적으로 300MW 이하로 설계되며, 탄소중립 목표달성과 재생에너지의 간헐성을 보완하는 백업 전원으로 활용이 기대된다.", related: [] },
  { id: 347, term: "속물효과(스놉효과)", definition: "개성을 추구하는 사람들이 단지 다른 사람들이 많이 구입한다는 이유만으로 특정 물품을 구입하지 않는 현상(스놉효과, Snob Effect). 특정 상품을 소비하는 사람이 많아질수록 그 상품에 대한 수요는 줄어든다.", related: ["기펜재", "밴드웨건효과", "베블런효과"] },
  { id: 348, term: "수요견인 인플레이션", definition: "경기과열 등으로 인해 개인들의 재화나 서비스에 대한 수요가 크게 늘면서 물가가 지속적으로 상승하게 되는 현상(Demand-Pull Inflation). 확대재정정책, 과도한 통화량 증가, 민간소비·투자의 갑작스러운 변동 등이 원인이다.", related: ["비용인상 인플레이션"] },
  { id: 349, term: "수요탄력성", definition: "상품의 가격 변화비율에 대한 수요량의 변화비율을 수요의 가격탄력성(price elasticity of demand)이라 한다. 탄력성이 1보다 크면 탄력적, 1보다 작으면 비탄력적, 1이면 단위 탄력적이라고 한다.", related: ["공급탄력성"] },
  { id: 350, term: "수익률곡선", definition: "이자율 기간구조(term structure)를 그래프로 나타낸 것(Yield Curve). 만기가 단기인 채권부터 장기인 채권 순으로 나열하여 연결한 곡선이다. 우상향 수익률곡선은 미래에 이자율이 상승할 것으로, 우하향 수익률곡선은 하락할 것으로 예상함을 시사한다.", related: ["장단기금리차"] },
  { id: 351, term: "수입유발계수", definition: "최종수요가 한 단위 증가할 때 각 산업부문에서 직·간접으로 유발되는 수입액 단위. 산업별 수입유발계수와 최종수요항목별 수입유발계수로 나뉜다.", related: ["생산유발효과"] },
  { id: 352, term: "수출경합도지수", definition: "특정 국가(Z)에 상품을 수출하는 두 국가(X와 Y)가 Z국 시장에서 직면하는 경쟁의 정도를 측정하는 지표(ESI). 지수가 100이면 경쟁도가 가장 높고, 0이면 가장 낮다.", related: ["현시비교우위지수(RCA)"] },
  { id: 353, term: "수출보험", definition: "상품수출 시 수출업자가 수입업자의 신용위험, 수입국의 정치상황 등으로 수출대금을 회수하지 못할 위험으로부터 수출업자를 보호하기 위한 보험. 한국무역보험공사 내에 수출보험기금을 설치하여 운영한다.", related: [] },
  { id: 354, term: "수출입물가지수", definition: "수출 및 수입상품의 가격변동을 측정하는 지표. 수출입관련업체들의 수출채산성 변동이나 수입원가 부담 등을 파악하는 한편 가격측면에서의 교역조건 등을 측정하는 데 이용된다. 2025년 8월 기준으로 수출물가지수 212개, 수입물가지수 237개 품목을 조사한다.", related: ["수출입물량지수"] },
  { id: 355, term: "수출입물량지수", definition: "무역지수 중 수출입물량의 변동을 나타내 주는 것으로 수출입금액지수를 수출입물가지수로 나누어 사후적으로 산출된다. 원유 등의 가격 변화에 따른 가격요인을 제외한 물량기준으로 수출입상황을 파악하는 데 활용된다.", related: ["수출입물가지수"] },
  { id: 356, term: "수쿠크", definition: "샤리아(Sharia) 율법을 지키기 위해 투자자들에게 이자수익 대신 배당금 혹은 리스료 형태로 수익을 배분하는 이슬람법 채권. 샤리아 율법은 이자 수취를 부당이득으로 간주하기 때문에 수쿠크는 특정 자산으로부터 취득할 수 있는 수익을 배당금 등의 형태로 배분한다.", related: ["이슬람금융"] },
  { id: 357, term: "수확체감의 법칙", definition: "자본과 토지는 일정하게 유지하고 노동의 투입량을 증가시킬 경우, 생산물 전체는 증가하지만 추가로 투입되는 노동량 1단위당 생산물의 증가는 차차 감소한다는 법칙(Law of Diminishing Returns). '한계생산력 체감의 법칙'으로 일반화되었다.", related: ["한계비용"] },
  { id: 358, term: "순상품교역조건지수", definition: "수출 1단위로 수입할 수 있는 상품의 양이 기준시점 대비 얼마나 증가하였는지를 나타내며, 수출가격물가지수를 수입물가지수로 나누어 산출한다. 지수가 상승하면 1단위 상품을 수출해서 이전보다 더 많은 양의 상품을 수입할 수 있게 된다.", related: ["무역지수", "수출입물가지수"] },
  { id: 359, term: "순안정자금조달비율", definition: "유동성을 감안한 은행 보유자산대비 안정적 조달자금(자본 및 부채)의 비율(NSFR; Net Stable Funding Ratio). 은행들은 2018년부터 NSFR 비율을 100% 이상으로 유지하여야 한다. 은행 자금조달 구조의 안정성을 강화하여 단기 도매 자금조달에 과도하게 의존하는 행태를 제한하기 위해 도입되었다.", related: ["유동성리스크"] },
  { id: 360, term: "순이자마진(NIM)", definition: "은행의 모든 금리부자산의 운용결과로 발생한 운용자금 한 단위당 이자순수익(운용수익률)을 나타내는 개념. 은행의 핵심 수익성 지표로, 이자자산순수익을 이자수익자산의 평잔으로 나누어 계산한다.", related: ["예대금리차(예대마진)"] },
  { id: 361, term: "순이체한도제", definition: "갈 참가기관으로 하여금 여타 참가기관과의 CD, 타행환 거래 등에서 발생하는 순이체액에 대하여 그 상한을 설정토록 함으로써 결제불이행 사태의 발생 가능성 및 불이행 규모를 최소화하도록 한 제도.", related: ["결제리스크", "차액결제시스템"] },
  { id: 362, term: "숨은 그림(은화)", definition: "은행권의 위조방지를 위한 장치의 하나로 은행권 용지를 빛에 비췄을 때 여백에 숨겨진 문양이 나타나도록 하는 장치. 오만원권에는 신사임당, 만원권에는 세종대왕, 오천원권에는 율곡 이이, 천원권에는 퇴계 이황이 나타난다.", related: ["은선"] },
  { id: 363, term: "스마트계약", definition: "블록체인을 이용하여 일정 조건이 만족되면 자동으로 거래가 실행되도록 작성된 컴퓨터 프로토콜 또는 코드(Smart Contract). 2015년 7월 비탈릭 부테린이 블록체인 기반 가상통화 플랫폼 서비스 '이더리움' 시작 후 확산되었다. 금융거래·부동산계약·공증·지적재산권 등 다양한 형태의 계약을 체결·이행할 수 있다.", related: ["블록체인"] },
  { id: 364, term: "스무딩오퍼레이션", definition: "자유변동환율제도하에서 일시적인 수급불균형이나 시장 불안심리 등으로 환율이 급변동하는 경우에 한해 외환당국이 외환시장에 개입하여 환율변동 속도를 조절하는 것(Smoothing Operation).", related: ["외환시장", "평가절상/평가절하"] },
  { id: 365, term: "스왑", definition: "거래 쌍방이 미리 정한 계약조건에 따라 일정 기간 주기적으로 원금이나 이자 등 현금흐름을 서로 교환하는 파생상품 계약(SWAP). 외환스왑(FX swap), 통화스왑(currency swap), 이자율스왑(interest rate swap) 등이 있다.", related: ["금리스왑", "통화스왑"] },
  { id: 366, term: "스왑레이트", definition: "현물환율 대비 선물환율과 현물환율의 차이를 연율(%)로 표시한 것으로, 이론적으로는 양 통화 간 금리차와 일치한다. 금융기관의 자금사정을 나타내는 대용지표(proxy)로도 활용된다.", related: ["금리평가이론"] },
  { id: 367, term: "스왑베이시스", definition: "통화스왑(CRS) 금리와 금리스왑(IRS) 금리의 차이(Swap Basis). CRS는 원화를 담보로 달러를 조달할 때 적용되는 금리로 달러 조달 비용을 나타내며, IRS는 원화 변동금리를 고정금리로 전환할 때의 수준으로 원화 고정 조달 비용을 의미한다.", related: ["금리스왑", "통화스왑"] },
  { id: 368, term: "스태그플레이션", definition: "실업과 인플레이션이 동시에 증가하는 현상. 스태그네이션(stagnation: 경기침체)과 인플레이션(inflation: 물가상승)을 합성한 용어로, 1970년대 두 차례의 유가파동을 겪으면서 낙대화되었다.", related: ["디플레이션", "장기침체"] },
  { id: 369, term: "스탠더드&푸어스(S&P)", definition: "무디스, 피치와 함께 세계 3대 국제신용평가기관. 채권의 신용등급을 AAA(최우량)부터 C(최저급)까지 매기며, 미국의 3대 주가지수인 S&P500지수도 발표한다.", related: ["무디스"] },
  { id: 370, term: "스테이블코인", definition: "가격변동성이 최소화되도록 설계된 가상자산. 법정화폐 담보형, 암호자산 담보형, 알고리즘형 등으로 분류된다. 가상자산을 이용한 지급 및 송금의 효율성 제고 등의 긍정적 효과가 기대되나 담보자산 가치하락 등으로 가격변동성이 확대될 가능성이 있다.", related: ["가상자산", "비트코인"] },
  { id: 371, term: "스톡옵션", definition: "회사가 임직원에게 일정기간이 지난뒤 자사 주식을 미리 정한 가격으로 살 수 있는 권리를 부여하는 제도(주식매수선택권). 직급이나 근속연수를 바탕으로 하는 우리사주제도와는 다르다.", related: ["옵션"] },
  { id: 372, term: "스트레스 DSR", definition: "변동금리 대출 등을 이용하는 차주가 금리 상승으로 인해 원리금 상환 부담이 증가할 가능성을 감안하여 DSR 산정시 일정 수준의 가산금리(스트레스 금리)를 부과하여 대출한도를 산출하는 제도. 2024년부터 3단계에 걸쳐 순차적으로 시행하였다.", related: [] },
  { id: 373, term: "스트레스 테스트(위기상황분석)", definition: "예외적이지만 발생가능한 위기 상황을 상정하여 개별 금융기관, 금융부문 및 금융시스템 전체의 취약성과 복원력을 평가하는 기법(Stress Test). 글로벌 금융위기를 계기로 거시 스트레스 테스트의 중요성이 높아지고 있다.", related: [] },
  { id: 374, term: "시뇨리지", definition: "화폐에 대한 독점적 발권력을 갖는 중앙은행이나 국가가 화폐발행을 통해 획득하는 이득(Seigniorage). 금속화폐 시대에는 화폐를 생산비용보다 높은 액면가치에 유통시킴으로써 발생하였다. 전통적으로 정부의 재정적자 보전수단으로 인식되었다.", related: ["중앙은행"] },
  { id: 375, term: "시스템 리스크", definition: "금융시스템의 일부 또는 전부가 부실화되면서 금융중개 기능이 정상적으로 수행되지 못할 위험. 횡단면적 경로(금융기관간 상호연계성 강화)와 시계열적 경로(경기순응성 강화)로부터 유발된다.", related: ["시스템적으로 중요한 금융기관"] },
  { id: 376, term: "시스템적으로 중요한 금융기관", definition: "규모가 크고 금융시스템 내 상호연계성이 높아 부실화 또는 도산 시 금융시스템에 광범위하고 중대한 영향을 미칠 수 있는 금융기관(SIFI). 대마불사(TBTF)의 기대를 강화시킬 우려가 있다. FSB와 BCBS는 매년 G-SIBs와 G-SIIs 명단을 선정하여 발표하고 있다.", related: ["시스템 리스크"] },
  { id: 377, term: "시장리스크", definition: "금융시장의 금리, 주가, 환율 등의 변동에 따라 은행이 트레이딩계정에 보유한 금융상품의 가격이 하락하여 손실이 발생할 가능성. 바젤은행감독위원회(BCBS)는 은행이 시장리스크에 상응하는 자기자본을 보유하도록 의무화하고 있다.", related: ["VaR(Value at Risk)"] },
  { id: 378, term: "시장평균환율(MAR)", definition: "외국환중개회사를 통해 거래가 이루어진 현물환매매 중 결제일 2영업일 전 현물환시장에서 형성되는 환율과 그 거래량을 가중평균하여 산출한 환율. 1990년 3월 도입되었다. 시장평균환율은 다음 영업일의 기준환율이 된다.", related: ["시장평균환율제도"] },
  { id: 379, term: "시장평균환율제도", definition: "우리나라가 1990년 3월 도입한 환율제도로, 1997년 외환위기 이전까지 시행되었다. 환율이 외환시장에서의 수요와 공급에 의해 결정되도록 하되, 급격한 환율 변동을 완화하기 위하여 환율의 일중변동 폭을 제한하였다. 1997년 12월 변동제한폭을 철폐함으로써 자유변동환율제도로 이행하였다.", related: ["고정환율제도/자유변동환율제도"] },
  { id: 380, term: "시카고상업거래소(CME)", definition: "세계 최대의 파생상품 거래소 중 하나. 1898년 농산물 거래소로 시작하여 1980년대들에는 통화선물 및 S&P500 선물 등을 상장하며 금융 선물시장을 개척하였다. 2007년 시카고상품거래소(CBOT)와 통합하여 CME 그룹이 되었다.", related: [] },
  { id: 381, term: "시카고 연준 금융상황지수", definition: "미국의 금융시장 상황을 지수화하여 현재 금융시장이 긴축적인지 또는 완화적인지를 나타내는 지수. 105개의 금융변수로 구성되며, 지수가 0을 기준으로 음수일수록 완화적, 양수일수록 긴축적임을 나타낸다.", related: [] },
  { id: 382, term: "신용경색", definition: "금융기관 등에서 돈의 공급이 원활히 이루어지지 않아 어려움을 겪는 현상(Credit Crunch). 일부 은행의 도산이나 부실화로 대출 가능 규모가 줄어들고, 건전한 은행들도 대출 규모를 축소하는 악순환이 발생한다.", related: ["신용위험(신용리스크)", "유동성리스크"] },
  { id: 383, term: "신용레버리지", definition: "레버리지효과를 거두기 위해 경제주체가 활용하고 있는 신용의 정도. 한국은행의 금융안정보고서에서는 민간신용/명목GDP 비율을 민간부문의 신용레버리지 수준으로 이용하여 분석한다.", related: ["레버리지 효과"] },
  { id: 384, term: "신용스프레드", definition: "특정 채권의 신용위험이 어느 정도인지를 보여주는 지표로서 동일만기 무위험 채권인 국고채 금리와 해당 채권 금리의 차이. 경기회복, 기업실적 개선 등으로 신용위험이 낮아질 때 축소되며, 경기침체 우려 등으로 신용위험이 높아질 때 확대된다.", related: ["신용위험(신용리스크)"] },
  { id: 385, term: "신용연계증권(CLN)", definition: "신용파산스왑(CDS)을 증권화한 형태. CLN 매도자는 기초자산의 신용상태와 연계된 증권을 발행하고 약정된 방식으로 이자를 지급하며, CLN 매수자는 약정이자를 받는 대신 신용사건 발생 시 기초자산의 손실을 부담하게 된다.", related: ["신용파생상품"] },
  { id: 386, term: "신용위험(신용리스크)", definition: "채권·채무관계에서 채무자의 채무불이행, 이행거부 또는 신용도 하락 등으로 인해 발생하는 손실 가능성을 포괄하는 개념. 부도율(PD), 손실율(LGD), 부도 시 익스포저(EAD) 등의 지표를 통해 체계적으로 산출된다.", related: ["예상손실"] },
  { id: 387, term: "신용창조", definition: "은행이 예금과 대출업무를 반복적으로 취급하는 과정에서 예금통화를 만들어내는 현상(Credit Creation). 100이라는 본원통화가 신용창조를 통해 1,000이라는 예금통화가 창출되며(지급준비율 10% 가정 시), 통화승수는 10이 된다.", related: ["지급준비제도", "통화승수", "본원통화"] },
  { id: 388, term: "신용파생상품", definition: "채권, 대출금 등과 같이 차입자의 신용에 따라 가치가 변동하는 기초자산의 신용위험을 분리하여 다른 거래상대방에게 이전하고 그 대가로 프리미엄을 지급하는 금융상품(Credit Derivative). 보장매입자는 보유채권의 신용위험 노출을 없애고, 보장매도자는 수수료 수입을 통해 수익증대를 도모할 수 있다.", related: ["신용위험(신용리스크)", "시장리스크"] },
  { id: 389, term: "신용평가제도", definition: "자금을 빌리는 가계, 기업 등 차입자의 부채 상환능력이나 신용도를 일정한 등급으로 평가하는 것. 신용평가회사(CRAs)는 채권을 발행하려는 기업이나 금융기관의 재무상황, 경제적 여건 등을 감안하여 발행자의 신용도를 등급으로 제시한다. 개인신용평가제도(CSS)는 대출여부 결정, 대출가능금액 및 적용금리 산정 등에 활용된다.", related: [] },
  { id: 390, term: "신용환산율", definition: "BIS 자기자본비율 계산시 난외자산의 명목원금에 신용환산율(Credit Conversion Factor)을 곱해서 산출된 신용리스크 상당액을 익스포저로 보는 개념. 난외자산이 실제로 활용되어 난내자산으로 전환될 확률 개념이다.", related: ["BIS 자기자본비율"] },
  { id: 391, term: "신·재생에너지", definition: "신에너지(연료전지, 석탄액화·가스화 및 수소에너지 3개)와 재생에너지(태양열, 태양광, 바이오, 풍력, 수력, 해양, 폐기물 및 지열 8개)를 포함. 기존 화석연료(석유, 석탄, 천연가스 등)와 우라늄을 대체할 수 있는 에너지이다.", related: ["탄소배출권"] },
  { id: 392, term: "신종자본증권", definition: "채권과 주식의 특성을 모두 보유한 금융상품. 용정 유동적, 금융회사의 경우 감독기관으로부터 자본으로 인정받을 수 있다. 우리나라에서는 2003년 4월 한국외환은행에서 최초 발행하였다.", related: [] },
  { id: 393, term: "신주인수권부사채(BW)", definition: "투자자가 미리 약정된 가격에 일정한 수량의 신주를 인수할 수 있는 권리인 워런트(Warrant)가 결합된 회사채. BW는 신주인수권 행사 시 인수권 부분만 소멸될 뿐 사채 부분은 계속 효력을 갖게 되므로 전환사채(CB)와 차이가 있다.", related: ["전환사채(CB)"] },
  { id: 394, term: "신흥시장국채권지수(EMBI+)", definition: "JP Morgan이 산출하는 신흥국 정부가 국제금융시장에서 발행한 달러화 표시 국채의 수익률을 기반으로 하는 대표적인 벤치마크 지수. EMBI+ 스프레드는 EMBI+ 수익률에서 미국 국채수익률을 차감한 값으로, 신흥국의 위험이 증가하면 동 스프레드가 커진다.", related: ["MSCI 지수", "FTSE 지수"] },
  { id: 395, term: "실망실업자", definition: "구직단념자라고도 하며, 노동시장적 사유로 지난 4주간 구직활동을 하지 않는 자 중 지난 1년 내 구직 경험이 있는 사람. 비경제활동인구 중 잠재구직자의 일부분이다.", related: ["고용보조지표", "자발적 실업"] },
  { id: 396, term: "실물화폐/명목화폐", definition: "실물화폐는 고유의 사용가치 및 교환가치를 가지고 화폐의 기능을 수행하는 물건(조개 등 귀한 물건 또는 교환의 도구로 사용하기에 적당한 가축, 면포 등). 소재가치와 교환가치가 다른 무엇을 화폐로 사용하게 되는 것을 명목화폐라고 하며, 오늘날에는 은행권(지폐)으로 대표된다.", related: [] },
  { id: 397, term: "실시간총액결제", definition: "금융기관간 지급액과 수취액을 상계시키지 않고 지급지시 건별로 그 지급지시의 금액(총액)을 실시간으로 이체하여 결제하는 방식. 신용리스크가 발생하지 않는다는 장점이 있다. 최근 소액지급시스템의 신속자금이체시스템도 이연결제방식에서 실시간총액결제방식으로 전환되고 있다.", related: ["차액결제시스템"] },
  { id: 398, term: "실업률", definition: "실업자수를 경제활동인구수로 나누어 백분율로 계산한 지표. 경제활동인구는 취업자와 실업자로 구분되는데, 실업자가 경제활동인구에 포함되는 이유는 일시적인 이유로 직장이 없으나 언제든지 노동력을 제공할 수 있는 인구로 분류되기 때문이다.", related: ["고용률", "고용보조지표"] },
  { id: 399, term: "실업률갭", definition: "실업률과 자연실업률간의 차이. 노동시장의 여력(slack)을 평가할 수 있는 유용한 지표로, GDP갭과 함께 경기수준 또는 경제 전반의 유휴자원을 파악할 때 유용하다. 실업률갭이 음(-)인 경우에는 노동공급 여력이 소진된 상황으로 인플레이션 압력이 높아질 가능성이 크다.", related: ["제조업평균가동률갭", "자연실업률"] },
  { id: 400, term: "실질구매력", definition: "물가수준을 고려한 구매력. 물가가 오르면 같은 금액으로 살 수 있는 양이 줄어들어 실질구매력은 낮아진다. 실질구매력 변화율은 명목임금 변동률에서 소비자물가 상승률을 차감하여 계산된다.", related: ["실질임금", "인플레이션"] },
];

import { newEntries } from './glossaryData_new_entries.js';
import { entries501to600 } from './glossaryData_501_600.js';
import { entries601to700 } from './glossaryData_601_700.js';
import { entries601to800 } from './glossaryData_601_800.js';
import { entries801to900 } from './glossaryData_801_900.js';
import { englishEntries } from './glossaryData_english.js';
export const allGlossaryTerms = [...glossaryTerms, ...newEntries, ...entries501to600, ...entries601to700, ...entries601to800, ...entries801to900, ...englishEntries];
const allTerms = allGlossaryTerms;

export const getTermsByLetter = (letter) => {
  return allTerms.filter(t => t.term.startsWith(letter));
};

export const searchTerms = (query) => {
  const q = query.toLowerCase();
  return allTerms.filter(t => 
    t.term.toLowerCase().includes(q) || 
    t.definition.toLowerCase().includes(q)
  );
};

export const koreanLetters = ['ㄱ', 'ㄴ', 'ㄷ', 'ㄹ', 'ㅁ', 'ㅂ', 'ㅅ', 'ㅇ', 'ㅈ', 'ㅊ', 'ㅋ', 'ㅌ', 'ㅍ', 'ㅎ'];

const initialMap = {
  'ㄱ': ['가', '갈', '강', '개', '거', '견', '결', '경', '계', '고', '골', '공', '과', '관', '광', '교', '구', '국', '규', '그', '근', '글', '금', '긴', '긴축', '꼬'],
  'ㄴ': ['낙', '난', '납', '내', '노', '녹', '뉴'],
  'ㄷ': ['단', '담', '당', '대'],
  'ㄹ': [],
  'ㅁ': [],
  'ㅂ': [],
  'ㅅ': [],
  'ㅇ': [],
  'ㅈ': [],
  'ㅊ': [],
  'ㅋ': [],
  'ㅌ': [],
  'ㅍ': [],
  'ㅎ': [],
};

export const getInitialConsonant = (str) => {
  const code = str.charCodeAt(0) - 0xAC00;
  if (code < 0) return str[0];
  const consonantIdx = Math.floor(code / 28 / 21);
  const consonants = ['ㄱ','ㄲ','ㄴ','ㄷ','ㄸ','ㄹ','ㅁ','ㅂ','ㅃ','ㅅ','ㅆ','ㅇ','ㅈ','ㅉ','ㅊ','ㅋ','ㅌ','ㅍ','ㅎ'];
  return consonants[consonantIdx];
};

export const getTermsByConsonant = (consonant) => {
  return allTerms.filter(t => getInitialConsonant(t.term) === consonant);
};